export const EFFECT_LIBRARY_DATA: CatalogEffect[] = [{"id":"per-word-pop","group":"kinetic-type","name":"Per-word kinetic reveal (E1)","what":"Each spoken word rises and fades in exactly as the voiceover says it, so text lands in sync with the narration.","how":"Copy is split into `<span class=\"w\" data-t=\"T\">word</span>` (display:inline-block; will-change:transform,opacity), T = VO word-start seconds. Script: `document.querySelectorAll('.w[data-t]').forEach(w=>{const t=parseFloat(w.dataset.t); tl.fromTo(w,{opacity:0,yPercent:70},{opacity:1,yPercent:0,durati","when":"Universal — every spoken line in every reel (hook, body, CTA). The backbone of the format."},{"id":"scribble-underline","group":"kinetic-type","name":"Hand-drawn scribble underline (E5)","what":"A rough marker squiggle draws itself under a key word as it is spoken.","how":"Wrap word in `.scribble` (position:relative) containing an inline `<svg>` positioned under the text with a wavy `<path>` (stroke-linecap:round, stroke-width ~8-10, stroke matches accent color). CSS seeds stroke-dasharray:1;stroke-dashoffset:1. Script: `tl.set('#scr',{strokeDasharray:320,strokeDashof","when":"Emphasize one loaded word in a hook or rehook ('scary', 'never', 'quietly', 'costs', 'two', 'empty', 'leave'). Common ac"},{"id":"text-strike-through","group":"kinetic-type","name":"Strike-through line (E6)","what":"A solid bar wipes horizontally across text/number to cancel it out ('Too late', missed money).","how":"Inside a relative wrapper, an absolutely-positioned bar `<div>` at top:52%, width:108%, height ~12px, background:currentColor, border-radius, transform:scaleX(0);transform-origin:left. Script: `tl.fromTo('#strike',{scaleX:0},{scaleX:1,duration:0.35-0.4,ease:'power2.inOut'},T)`. Also used as red 'lea","when":"Kill a value or negate a phrase — 'missed money', 'Too late', 'No call/No form/No name'. Pair with impact SFX."},{"id":"marker-highlight-sweep","group":"kinetic-type","name":"Marker highlight sweep behind word (E4)","what":"A colored highlighter block grows left-to-right behind a word, then the word text turns white on top of it.","how":"reel-07 `.mark{position:relative;z-index:0}` with `.mark::before{content:'';position:absolute;z-index:-1;left:-8px;top:12%;bottom:8%;width:calc((100% + 16px) * var(--mkw,0));background:var(--blue);transform-origin:left;border-radius:6px}`. Script drives a proxy: `const mk={p:0}; tl.to(mk,{p:1,durati","when":"Highlight the single payoff word in a value line ('fresh' angles). Editorial emphasis without a full color scene."},{"id":"word-highlight-box","group":"kinetic-type","name":"Inline word chip / boxed word","what":"One word sits inside a solid rounded box (a highlighter chip) to mark it as the answer/winner.","how":"Inline style on the `.w` span: `style=\"background:#fff;padding:0 8px;border-radius:8px\"` (reel-07 'winner') so the word reads as a physical label. Static styling; still pops via the per-word-pop fromTo. Seek-safe.","when":"Call out the literal keyword of the beat ('winner') mid-sentence."},{"id":"type-ladder-compare","group":"kinetic-type","name":"Big-number type ladder (E11)","what":"Two stacked oversized figures (e.g. '50 happy' over '★4 reviews') scale-bounce in to contrast quantity.","how":"reel-03 `.ladder` column of `.lad-row` (flex baseline) each with a huge `.lad-big` serif number + a mono `.lad-cap`. Script bounces each: `tl.fromTo('#lad50',{scale:0.4,opacity:0},{scale:1,opacity:1,duration:0.5,ease:'back.out(2.4)'},T)` and the smaller one with a follow-up pulse `.to(...,{scale:1.0","when":"Hook that contrasts two magnitudes (lots of X vs tiny Y)."},{"id":"stacked-line-cta","group":"kinetic-type","name":"Stacked-list CTA lines","what":"The CTA reads as a vertical stack of huge lines ('Book a / free / AI audit.') for punch.","how":"reel-04 `.stack{display:flex;flex-direction:column;align-items:center}` of `.ln` spans (position:relative;overflow:hidden) each holding a `.w` word; the light-sweep element lives in the last `.ln`. Words still use per-word-pop. Seek-safe.","when":"Final CTA card when you want maximal vertical weight."},{"id":"scene-hardcut-autoalpha","group":"cut-transition","name":"Scene hard-cut in/out (autoAlpha)","what":"Each beat snaps on and off instantly at its data-in/data-out time — no crossfade, MTV-style cutting.","how":"For every `.scene`: `tl.set(sc,{autoAlpha:1},dataIn)` ... `tl.set(sc,{autoAlpha:0},dataOut)`. autoAlpha toggles opacity+visibility together. Scenes are absolute inset:0 and initially opacity:0;visibility:hidden. Seek-safe (pure set()).","when":"Every scene boundary. The structural cut of the whole format."},{"id":"scene-cut-zoom-through","group":"cut-transition","name":"Zoom-through cut entry (E14)","what":"On even scenes the beat starts slightly zoomed-in and blurred, then snaps sharp — a punch-in feel.","how":"In the .scene loop, `if(idx%2===0) tl.fromTo(sc,{scale:1.04,filter:'blur(8px)'},{scale:1,filter:'blur(0px)',duration:0.24,ease:'power2.out',overwrite:'auto'},dataIn)`. Seek-safe.","when":"Alternating scene entries to vary rhythm; automatic by index parity."},{"id":"scene-cut-zoom-blur","group":"cut-transition","name":"Zoom-out-of-blur cut entry (E19)","what":"On odd scenes the beat starts slightly zoomed-out and blurred, then resolves in — a settle feel.","how":"In the .scene loop, `else tl.fromTo(sc,{scale:0.96,filter:'blur(6px)'},{scale:1,filter:'blur(0px)',duration:0.24,ease:'power3.out',overwrite:'auto'},dataIn)`. Alternates with zoom-through by idx%2. Seek-safe.","when":"Alternating scene entries; automatic by index parity."},{"id":"shutter-flash-cut","group":"cut-transition","name":"White shutter flash (E50)","what":"A full-screen white flash punctuates a big moment (the turn, a latch, a reveal).","how":"A fixed `<div id=\"flash\">` (inset:0;z-index:80;background:#fff;opacity:0). Script: `tl.to('#flash',{opacity:0.55-0.85,duration:0.05},T).to('#flash',{opacity:0,duration:0.2-0.24},T+0.05)`. Seek-safe. Usually placed exactly on an impact SFX.","when":"The turn/pivot beat, count-up latches, winner reveals, booking confirmations."},{"id":"red-flash-death","group":"cut-transition","name":"Red flash (deal/urgency)","what":"The shutter flash tinted red to signal something dying or failing.","how":"reel-10 reuses #flash but sets backgroundColor:'#FF3B2F' in the flash-up tween: `tl.to('#flash',{opacity:0.55,duration:0.05,backgroundColor:'#FF3B2F'},T).to('#flash',{opacity:0,duration:0.3},T+..)`; restores '#fff' onComplete for later white flashes. Seek-safe (restore in onComplete is fine because ","when":"Sale-dies / deal-dead beats. Pair with a fail tone."},{"id":"background-color-rotation","group":"layout","name":"Beat-to-beat background rotation (black/white/accent)","what":"The whole screen background flips between black, white, and the accent color from beat to beat to drive energy.","how":"Each `.scene` carries one of `.bg-k` (black radial), `.bg-w` (white/cream radial), `.bg-o` (accent radial — orange, or blue in reels 04/07). Choice is authored per section, not animated. Text color inverts via the scene class. The pattern: black=tension, white=clarity/turn/demo, accent=punch/CTA.","when":"Structural — assign per beat by emotional role. Universal."},{"id":"vertical-scene-layout","group":"layout","name":"Centered vertical scene stack (1080x1920)","what":"Every beat centers a headline + one hero device in a portrait 9:16 column with generous gaps.","how":"`.scene{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:56px;padding:0 96px;text-align:center}`. Root #comp is 1080x1920 overflow:hidden. Headline sizes via `.head`/`.head.sm`/`.head.xl`/`.head.tiny`. Static layout.","when":"Every scene. The canonical reel frame."},{"id":"phone-call-card","group":"ui-mockup","name":"Incoming phone-call card","what":"A phone-shaped card shows an avatar, 'New customer', and a blinking INCOMING… label with expanding call rings.","how":"`.card.phone` (rounded 50px) holds `.rings`(absolute)+`.avatar`(radial circle, emoji)+`.caller`+`.callsub`. Rings are ambient CSS: `.rings i{border:3px solid orange;animation:ring 1.6s linear infinite}` with `@keyframes ring{0%{scale(1);opacity:.7}100%{scale(2.3);opacity:0}}` (decorative loop, allow","when":"Missed-call / receptionist hooks (reels 01, 06). Establishes the 'phone is ringing' problem."},{"id":"status-banner","group":"ui-mockup","name":"Status banner (MISSED / AI ANSWERED)","what":"A pill banner on the phone card reads MISSED (red) or AI ANSWERED ✓ (orange) to flip the outcome.","how":"`.banner.missed{background:rgba(255,85,69,.15);color:#ff6a5a;border...}` and `.banner.ai{orange tint}`. Revealed with the scene; the AI version usually paired with a scale-bounce on the card and a shutter flash. Static style + fromTo reveal.","when":"Problem state (MISSED) vs solution state (AI ANSWERED) on phone cards."},{"id":"voice-wave-bars","group":"ui-mockup","name":"Voice waveform bars","what":"A row of vertical bars bounce like an audio waveform to imply a live voice/answer.","how":"reel-01 `.wave` flex row of `<span>`s; ambient CSS `@keyframes wv{0,100%{height:20px}50%{height:78px}}` with staggered animation-delay via nth-child. Decorative loop (allowed, non-load-bearing). Bars sit under a 'Answered in 1 ring · 24/7' label.","when":"AI-receptionist 'picks up / answers' beats."},{"id":"whatsapp-chat-thread","group":"ui-mockup","name":"WhatsApp chat device","what":"A faithful WhatsApp thread (green header, avatar, online/typing status, bubbles with timestamps and ✓✓) that springs alive.","how":"reel-02 `.wa` card: `.wa-top`(green #128C7E header, `.wa-av`, `.wa-name`, `.wa-status` with a glowing `.wa-dot`) + `.wa-body` holding `.bub.them`(grey #1f2c33)/`.bub.me`(green #005c4b), each with a `.time` sub. The whole device enters `tl.fromTo('#wa7',{scale:0.8,opacity:0},{scale:1,opacity:1,ease:'","when":"WhatsApp/messaging reels (reel-02). Both the 'you ignored it' and the 'AI never sleeps' halves."},{"id":"sms-chat-bubble-pop","group":"ui-mockup","name":"Chat / SMS bubble pop (E22)","what":"Message bubbles drop or pop into a thread one per beat, alternating sides (them vs AI).","how":"Generic `.chat` column with `.bub.them`(dark card, left, small bottom-left radius) and `.bub.ai`(accent fill, right). Each starts opacity:0. Reveal: `tl.fromTo('#b1',{opacity:0,y:18-26,scale:0.9?},{opacity:1,y:0,scale:1,duration:0.28-0.34,ease:'power2.out' or 'back.out(2)'},T)`. Timestamps/meta via ","when":"Any 'AI answers / asks / replies' demo beat (reels 01,02,03,04,05,06,10)."},{"id":"typing-dots","group":"ui-mockup","name":"Typing indicator dots (E9)","what":"Three dots bounce in a bubble to show the AI is 'typing', then vanish just before the reply appears.","how":"`.typing` bubble with three `<i>` dots; ambient CSS `@keyframes tdot/tp{translateY bob + opacity}` staggered by nth-child animation-delay. Timeline reveals/hides it: `tl.fromTo('#typ',{opacity:0},{opacity:1},T); tl.to('#typ',{opacity:0,duration:0.15},T+..)` right before the reply bubble pops.","when":"Between a customer question and the AI's instant reply, to sell 'live'."},{"id":"rival-villain-card","group":"ui-mockup","name":"Rival 'Booked' card (E2/E21)","what":"A competitor's card springs in stamped ✓ Booked / ✓ Answered — the customer went to them.","how":"`.rival` row (name + tag) or `.card.rival`. Enter with `tl.fromTo('#rival',{scale:0.9,opacity:0.4},{scale:1,opacity:1,duration:0.4,ease:'back.out(2)'},T)`. Sometimes the tag color-flips (`tl.fromTo('.tag',{color:'#8a8f99'|'#B8FF2C'},{color:accent},T)`) and ambient `.ringdots` pulse. Seek-safe.","when":"The 'they called the next business' / 'a faster rival won' villain beat. Recurs in reels 01,02,03,04,06."},{"id":"calendar-self-book","group":"ui-mockup","name":"Calendar self-booking row (E23)","what":"A day/time row in a mini calendar flips from grey to accent-filled and stamps ✓ Booked.","how":"`.cal` with `.row` items; the target `.row.book`. Script: `tl.fromTo('#calbook',{backgroundColor:'#0e1016',color:'#8a8f99'},{backgroundColor:accent,color:ink,duration:0.3},T)` then `tl.fromTo('#calchk',{opacity:0,x:-10},{opacity:1,x:0,ease:'back.out(2)'},T+..)`. Often followed by a spark burst. Seek","when":"Payoff beat where the AI books the job (reels 01,02,04,06,09)."},{"id":"browser-window-mockup","group":"ui-mockup","name":"Browser window chrome","what":"A mini browser (three dots + URL bar + page body) frames a website or landing page.","how":"`.browser` card with `.bbar`/`.brbar` (three round `<b>`/`.dot` + `.burl`/`.url` mono text) over a `.bbody`/`.page` body. Enters with a scale-bounce `tl.fromTo('#br',{scale:0.94,opacity:0.5},{scale:1,opacity:1,ease:'back.out(1.6)'},T)`. Body content varies by reel (chat widget, page blocks, form fie","when":"Website-chat and landing-page reels (05, 08)."},{"id":"chat-widget-bubble","group":"ui-mockup","name":"Site chat-widget launcher","what":"A round chat-bubble launcher pops into the corner of the browser, then a conversation appears.","how":"reel-05 `.widget` (absolute bottom-right circle, lime fill, 💬). Pops: `tl.fromTo('#wgt',{scale:0},{scale:1,ease:'back.out(2.4)'},T)`; bubbles follow via sms-chat-bubble-pop. Seek-safe.","when":"'AI chat greets every visitor' demo (reel-05)."},{"id":"landing-page-mockup-flags","group":"ui-mockup","name":"Landing page with problem flags","what":"A landing page (headline block, CTA button, form fields) gets red ✕ flags pinned to weak spots.","how":"reel-08 `.page` body with `.pg-h`/`.pg-sub`/`.pg-cta`/`.pg-form`(`.pg-fld` rows). `.flag`(absolute, red-tinted pill, opacity:0) pops per issue: `tl.fromTo('#fl4',{opacity:0,scale:0.7,x:20},{opacity:1,scale:1,x:0,ease:'back.out(2.2)'},T)`. Card can shake on a negative word. Seek-safe.","when":"Diagnosing a landing page — weak headline / long form / no proof (reel-08)."},{"id":"scan-line-sweep","group":"ui-mockup","name":"AI scan-line sweep (E27)","what":"A glowing horizontal line sweeps down a page to show the AI auditing/scanning it.","how":"reel-08 `#scanline` (absolute full-width, 5px, gradient with orange glow box-shadow) inside an overflow:hidden page. `tl.fromTo('#scanline',{top:'0px'},{top:'420px',duration:1.4,ease:'power1.inOut'},T)`. Seek-safe.","when":"'An AI audits your page' scanning beat."},{"id":"audit-checklist-tick","group":"ui-mockup","name":"Audit checklist rows tick on (E23/E24)","what":"Checklist rows (Headline, Buttons, Form, Mobile) light up and stamp a ✓ box one per spoken item.","how":"reel-08 `.audit` of `.aud-row`(opacity:.35) each with a `.box`. Per item: `tl.to(id,{opacity:1},t); tl.fromTo(id,{borderColor:'#2a2f3a'},{borderColor:accent},t); tl.fromTo(id+' .box',{scale:0.4,opacity:0},{scale:1,opacity:1,ease:'back.out(2.4)'},t+0.02)`. Timed to VO word beats. Seek-safe.","when":"Listing what the AI checks/fixes, item by item."},{"id":"match-mismatch-flip","group":"ui-mockup","name":"Ad ≠ Page → = flip (E12)","what":"Two tiles (Your ad / Your page) sit either side of a red ≠ that snaps to a green = .","how":"reel-08 `.matchwrap` of two `.mtile` + a center `.mlink` glyph. Enter red ≠: `tl.fromTo('#mlink',{scale:0.6,opacity:0,color:'#ff5545'},{scale:1,opacity:1,ease:'back.out(2)'},T)`; then swap glyph+color: `tl.to('#mlink',{color:'#B8FF2C',scale:1.15,yoyo:true,repeat:1,onStart:()=>el.textContent='='},T2)","when":"'Does your page even match your ad?' message-match beat."},{"id":"price-quote-doc-card","group":"ui-mockup","name":"Price / quote / proposal document card (E24)","what":"A branded invoice/quote card with line items and a big total slides in, later going grey/'silent' or reviving with follow-up ticks.","how":"reel-02 `.price`(rows + lime `.total`) and reel-10 `.quote`(`.qhead` title+`.qtag` status pill, `.qline` rows, `.qtotal` serif amount). Enters `tl.fromTo('#card',{scale:0.9,opacity:0,y:24},{scale:1,opacity:1,y:0,ease:'back.out(1.8)'},T)`; status pill pulses; total can count up (see count-up). Dead s","when":"Sends-the-price beat (reel-02) and quote-follow-up story (reel-10)."},{"id":"voicemail-card","group":"ui-mockup","name":"Voicemail card","what":"A 'Voicemail (0:00)' card with 'nobody listens…' that color-flips red.","how":"reel-06 `.vm` row (icon tile + text). Enter fromTo y/opacity; sub text color-flip `tl.to('#vmsub',{color:'#ff5545'},T)`. Seek-safe.","when":"'Most people who hit your voicemail never try again' beat."},{"id":"reminder-phone-notif","group":"ui-mockup","name":"Reminder phone + ping ripple","what":"A phone card with a 🔔 wiggling and expanding ping rings as a reminder notification slides in.","how":"reel-09 `.rmphone` card with `.pingwave` (three `<i>` rings), a `.bell`, and `.rmnotif`. Notif: `tl.fromTo('#rmnotif',{opacity:0,y:18,scale:0.96},{opacity:1,y:0,scale:1,ease:'back.out(1.6)'},T)`. Ping rings staggered: rings.forEach `tl.fromTo(el,{opacity:0.6,scale:0.6},{opacity:0,scale:2.2,duration:","when":"'It sends a reminder the day before' no-show beat (reel-09)."},{"id":"waitlist-recovery-rows","group":"ui-mockup","name":"Waitlist auto-fill rows","what":"Rows show a slot dropping (red), the next person offered, then booked (lime) with a spark.","how":"reel-09 `.wl` list of `.wlrow`(opacity:0). Stagger in with x/opacity fromTo; the dropped row's status turns red `tl.to('#wl1st',{color:'#ff5545'},T)`; the booked row border→lime `tl.to('#wl3',{borderColor:'rgba(184,255,44,0.55)'},T)` plus a spark burst. Seek-safe (avoid className set() for reverse-s","when":"'If someone drops, it fills the slot from your waitlist' beat (reel-09)."},{"id":"cost-rows-dock","group":"ui-mockup","name":"Cost rows dock in one per beat","what":"Rows ('Staff, waiting — still paid', 'Rent — still due', 'That booking — gone') slide in from the left as narration lists them.","how":"reel-09 `.costs` of `.costrow`(opacity:0). Each: `tl.fromTo('#cost1',{opacity:0,x:-24},{opacity:1,x:0,ease:'power2.out'},T)` timed to the VO word. Seek-safe.","when":"Enumerating hidden costs while speaking them."},{"id":"review-request-chat-star-stamp","group":"ui-mockup","name":"Review-request chat + star stamp","what":"The AI asks for a review, the customer replies ★★★★★, and a giant star row stamps in.","how":"reel-03 `.chat` (`.bub.ai`/`.bub.you`) plus a `.stampstars` row. Bubbles fromTo y/opacity on beats; stars stamp `tl.fromTo('#ca3',{opacity:0,scale:0.6},{opacity:1,scale:1,ease:'back.out(2.4)'},T)` with a ding SFX. Seek-safe.","when":"'AI asks at the perfect moment' review demo (reel-03)."},{"id":"route-to-private-inbox","group":"ui-mockup","name":"Route unhappy → private inbox (E27)","what":"A 😕 face card, a down arrow, and a '🔒 Private inbox ✓ Routed' pill show negative reviews being intercepted.","how":"reel-03 `.route` column: `.facecard` bounces in, `.arrow` drops (`tl.fromTo('#rarrow',{opacity:0,y:-14},{opacity:1,y:0},T)`), then `.privchk` stamps (`back.out(2)`). Seek-safe.","when":"'Sends the unhappy ones to you first' review-gating beat (reel-03)."},{"id":"creative-ab-grid","group":"ui-mockup","name":"Creative A/B ad grid (E28)","what":"A grid of ad cards staggers in; some stamp FATIGUED and grey out, one gets a blue winner border + crown while losers dim.","how":"reel-07 `.grid` of `.adcard`(thumb, line1/line2, CTR/CPL stat). Stagger: forEach `tl.fromTo(c,{opacity:0,y:26,scale:.9},{opacity:1,y:0,scale:1,ease:'back.out(1.6)'},T+n*0.16)`. State classes (.dead FATIGUED stamp via ::after, .winner border+glow, .faded, crown) are toggled REVERSE-SAFELY in a single","when":"Meta-ads creative-testing reel (reel-07): burnout, generation, side-by-side test, winner."},{"id":"eye-scroll-past","group":"ui-mockup","name":"Eye + ad scroll-past (E39)","what":"An 👁️ next to a small ad; the ad drifts up and fades as if being scrolled past.","how":"reel-07 `.scrollrow` (eye + `.adsm`). `tl.fromTo('#ad5',{y:0,opacity:1},{y:-120,opacity:0.25,ease:'power2.in'},T)` + eye pulse. Seek-safe.","when":"'The more they see the same ad, the more they scroll past it' fatigue beat."},{"id":"lead-card-live","group":"ui-mockup","name":"Live lead card","what":"A 'New lead · web form — JUST LANDED' card with a glowing green live dot.","how":"reel-04 `.card.lead` with a `.dotlive`(green, box-shadow glow) + text. Enter `tl.fromTo('#leadcard',{scale:0.9,opacity:0},{scale:1,opacity:1,ease:'back.out(2)'},T)`; instant AI reply bubble follows. Seek-safe.","when":"'AI answers instantly the second it landed' speed-to-lead beat (reel-04)."},{"id":"hot-lead-flag-card","group":"ui-mockup","name":"Hot-lead flag card + glow","what":"A lead card lights a '🔥 Hot reply' flag with a pulsing red glow border, then stamps 'Booked ✓'.","how":"reel-10 `.hotcard` with `.hotglow`(absolute inset:-3px border, opacity:0) + `.flag`. Flag: `tl.fromTo('#hotflag',{opacity:0,x:14},{opacity:1,x:0,ease:'back.out(2)'},T)`. Glow pulse: `tl.fromTo('#hotglow',{opacity:0},{opacity:1},T).to('#hotglow',{opacity:0.35,yoyo:true,repeat:3,ease:'sine.inOut'},T+.","when":"'The second a lead goes hot, it flags them for you' beat (reel-10)."},{"id":"count-up-odometer","group":"data-viz","name":"Number count-up (E31)","what":"A number rolls up from a start value to a target ($0→$90,000, 1→21×, 4.9, $18→$47, 4%→36%, 30 variations).","how":"Tween a plain proxy object and write text in onUpdate: `const v={v:0}; tl.to(v,{v:90000,duration:1.1,ease:'power1.out',onUpdate:()=>el.textContent='$'+Math.round(v.v).toLocaleString('en-US')},T)`. Percentages append '%'; decimals use toFixed(1); currency uses toLocaleString. Fully seek-safe (state d","when":"Money reveals, multipliers, ratings, cost meters, counts. Everywhere numeric emphasis is needed."},{"id":"count-down-odometer","group":"data-viz","name":"Number count-DOWN","what":"A number falls (30→0 timer, 100→3 visitors, 100%→5% odds, 100%→12% warmth).","how":"Same proxy-tween pattern with a descending target: `const tc={v:30}; tl.to(tc,{v:0,duration:2.4,ease:'power1.inOut',onUpdate:()=>el.textContent=Math.round(tc.v)},T)`. Often paired with a ring/meter draining in sync. Seek-safe.","when":"Timers, dwindling odds, leads leaving, warmth cooling (reels 05,06,04,02)."},{"id":"meter-fill-bar","group":"data-viz","name":"Horizontal meter fill/drain (E32)","what":"A gradient bar scales left-to-right to show a rising/falling metric (answered %, bounce %, odds, warmth, CPL, conversion, deal-alive).","how":"`.meterbar`(track) contains `.meterfill`(gradient, transform:scaleX(0);transform-origin:left). `tl.to('#mfill',{scaleX:0.42,duration:1.4,ease:'power2.out'},T)` fills; drain uses scaleX toward 0. Often a paired count-up updates the % label. Warmth cool adds `filter:'saturate(0) brightness(.6)'` in th","when":"Any single-metric gauge — % answered, % bounced, odds, cost/lead, conversion, deal health."},{"id":"comparison-bars","group":"data-viz","name":"Comparison bars (4 vs 40) (E34)","what":"Two stacked bars draw to different widths to contrast you vs a rival, the winner stamped with stars.","how":"reel-03 `.bars` of `.barrow`(label + `.bartrack` + `.barfill` with per-bar width%: `.you{width:10%}`,`.rival{width:100%}` and transform:scaleX(0)). Draw: `tl.to('#youfill',{scaleX:1,ease:'power2.out'},T)`, `tl.to('#rivfill',{scaleX:1},T2)`; `.barstars` fades in on the rival bar with a small pulse. S","when":"Head-to-head quantity contrast (reviews you vs them)."},{"id":"donut-ring-fill","group":"data-viz","name":"5-star donut ring fill (E35)","what":"A circular progress ring sweeps ~98% around a ★★★★★ / 4.9 center as it counts up.","how":"reel-03 SVG two circles: `.donut-bg` + `.donut-fg`(stroke-linecap:round, dasharray:1). SVG rotated -90deg so it starts at top. Compute `C=2*Math.PI*R`; `tl.set('#donutfg',{strokeDasharray:C,strokeDashoffset:C},T); tl.to('#donutfg',{strokeDashoffset:C*0.02,duration:1.6,ease:'power2.out'},T2)`. Center","when":"Rating payoff (reel-03 '4.9')."},{"id":"timer-ring-countdown","group":"data-viz","name":"Countdown timer ring (E32)","what":"A 30-second ring depletes while the center number counts 30→0.","how":"reel-06 SVG `.ringbg`+`.ringfg`(dasharray fixed 880, dashoffset 880) rotated -90deg. `tl.fromTo('#tring',{strokeDashoffset:880},{strokeDashoffset:0,duration:2.4,ease:'power1.inOut'},T)` in sync with a 30→0 count-down proxy. Number pulses on the key word. Seek-safe.","when":"'Send one text in thirty seconds' urgency device (reel-06)."},{"id":"confirm-ring-check","group":"data-viz","name":"Confirmation ring + check","what":"A green ring and giant ✓ pop in with a spark burst to confirm a booking.","how":"reel-09 `.confwrap` with `.confring`(border circle, opacity:0) + `.confcheck`. `tl.fromTo('#confring',{opacity:0,scale:0.4},{opacity:1,scale:1,ease:'back.out(2)'},T)` then `tl.fromTo('#confcheck',{opacity:0,scale:0.3},{opacity:1,scale:1,ease:'back.out(2.4)'},T+.1)` + spark burst + shutter flash. See","when":"'AI confirms every booking the moment it's made' beat (reel-09)."},{"id":"decay-curve-chart","group":"data-viz","name":"Value decay curve draw + tracer (E34)","what":"An SVG line chart draws itself (lead value peaks then dies) with a dot riding the peak, then plunging.","how":"reel-04 SVG `.chart` with grid/axis lines and a `<path class=curve>`. Measure `len=path.getTotalLength()`, `tl.set(curve,{strokeDasharray:len,strokeDashoffset:len},T); tl.to(curve,{strokeDashoffset:0,duration:1.9,ease:'power1.inOut'},T)` to draw. A `#curveDot` rides via attr tween: `tl.to('#curveDot","when":"Speed-to-lead value-over-time story (reel-04): peak, death, cliff."},{"id":"flat-fast-line","group":"data-viz","name":"Flat 'always-on' line","what":"A short green horizontal line draws instantly with a dot racing across — the 'reply the second it lands' ideal.","how":"reel-04 `#flatLine` path, `getTotalLength` + strokeDashoffset draw over 0.5s, then `#flatDot` attr tween cx to the end. Green `.curve.flat` variant. Seek-safe.","when":"The turn where instant response flattens the decay (reel-04)."},{"id":"dot-grid-field","group":"data-viz","name":"Visitor dot field (E41)","what":"A grid of ~100 dots representing website visitors appears; most drift/scatter away leaving a glowing few.","how":"reel-05 builds dots in JS: `buildField(el,n,cols)` computes a grid and appends `.dot` divs at absolute px positions. Appear staggered: `dots1.forEach((d,i)=>tl.fromTo(d,{opacity:0,scale:0},{opacity:1,scale:1,duration:0.02},0.15+i*0.021))`. To scatter, a seeded PRNG (mulberry32) gives deterministic o","when":"Website-traffic reel (reel-05): 100 visited, 97 left."},{"id":"funnel-leak","group":"data-viz","name":"Funnel with leaking dots","what":"Click-dots pour into a funnel shape; most leak out the sides (only 4 stay), then after the 'fix' they flow through and the count rises.","how":"reel-08 SVG `.fwall` funnel path + a `.dotfield`; `seedDots(host,n,x0,x1,y0,y1)` places `.vdot`s using a seeded LCG rnd(). Dots drop in (fromTo y), then `if(k>=4)` leak out: `tl.to(d,{opacity:0,x:side*(180+rnd()*120),y:220+rnd()*160},T)`, else funnel down. The recovery scene reseeds and funnels most","when":"Landing-page leak vs seal story (reel-08)."},{"id":"chip-dock-equation","group":"data-viz","name":"Chips dock in one per beat (E33)","what":"Small labeled chips (Ads, SEO, Social, Email — or Follow-up 1..6) pop/dock in sequence, some highlighting on.","how":"reel-05 `.chips` of `.chip`(opacity:0, data-t) — forEach: `tl.fromTo(ch,{opacity:0,y:24,scale:0.8},{opacity:1,y:0,scale:1,ease:'back.out(2)'},t)` then `tl.to(ch,{borderColor:accent,color:accent},t+0.04)`. reel-10 `.fups` uses the same pattern with a `.on` highlight on the first. Seek-safe.","when":"Enumerating cost sources or required follow-ups while listing them."},{"id":"clock-hands-spin","group":"data-viz","name":"Clock face hands spinning (E31)","what":"An analog clock's hands sweep from one time to another (11:04PM → noon; land on 3:00) with a digital label counting.","how":"reel-02 `.clock` circle with `.hand.hh`/`.mh`(transform-origin bottom center) + `.pin`. Set start rotations, then `tl.to('#hh3',{rotation:390,duration:1.1,ease:'power2.inOut'},T)`; a paired proxy `{h,m}` updates the digital `.clocklbl` via onUpdate with AM/PM math. reel-04 uses a minute-hand-only sw","when":"Time-passing / 'you replied hours later' beats (reels 02, 04)."},{"id":"cpl-fatigue-meter","group":"data-viz","name":"Cost-per-lead climbing/dropping meter","what":"A big $ value + bar climbs (hot gradient) as costs rise, then drops with a cool blue gradient after the fix.","how":"reel-07 `.meterwrap` with a `.metertop` big value + `.meterbar/.meterfill`. Climb: fill scaleX + $ count-up ($18→$47) with power2.in; relief: `.meterfill.cool` (blue gradient) drains + $47→$12 count-down. Value pulses on stress words. Seek-safe.","when":"Ad-cost pain then relief (reel-07)."},{"id":"empty-days-counter","group":"data-viz","name":"Giant empty-days counter","what":"A huge number counts up to 6 ('empty days this month') and shakes on impact.","how":"reel-09 `.counter` huge figure + `.unit` sublabel. Bounce in `back.out(2)`, count-up proxy 0→6, then impact shake `tl.to('.counter',{x:-10,duration:0.05,yoyo:true,repeat:7,ease:'none'},T)`. Seek-safe.","when":"'You find out when nobody walks in' no-show cost beat (reel-09)."},{"id":"film-grain-overlay","group":"ambience","name":"Film grain overlay (E36)","what":"A subtle static grain texture sits over everything for a filmic, non-flat look.","how":"`<div id=\"grain\">` inset:0;z-index:70;opacity:.06;mix-blend-mode:overlay with a data-URI SVG feTurbulence fractalNoise as background-image. Static (no timeline). Present in every reel.","when":"Always-on ambience. Set once."},{"id":"vignette-radial-glow","group":"ambience","name":"Vignette + radial glow (E37)","what":"Edges darken and the center gets a soft glow to focus the eye.","how":"`<div id=\"vign\">` inset:0;z-index:71;background:radial-gradient(120% 85% at 50% 42%,transparent 55%,rgba(0,0,0,.4) 100%). Scene backgrounds are themselves radial-gradients providing the center glow. Static. Every reel.","when":"Always-on ambience."},{"id":"dust-silence-particles","group":"ambience","name":"Drifting dust / silence particles (E49)","what":"Faint particles drift upward off a 'gone quiet' card to sell abandonment/silence.","how":"reel-10 `.dust` container; JS appends `<i>` dots at seeded positions (mulberry32) and animates each: `tl.fromTo(d,{opacity:0,y:0},{opacity:0.5,y:-30-rnd()*40,duration:0.8+rnd()*0.5},1.1+rnd()*0.4)` then fade out. A `.quiet` overlay ('silence…') fades in. Seek-safe (seeded).","when":"The 'then nothing / it went silent' emotional beat (reel-10)."},{"id":"dot-grid-css-overlay","group":"ambience","name":"Masked dot-grid backdrop (E41)","what":"A faint dotted grid fades in behind the scene, masked toward the center, for a 'data/world' texture.","how":"reel-05 `.dotgrid::before` radial-gradient dot pattern (background-size:64px) with a radial mask-image so it fades at edges; `.scene>*{position:relative;z-index:1}` keeps content above. Static class on chosen scenes.","when":"Scenes about many people/visitors (reel-05)."},{"id":"scale-bounce-reveal","group":"motion-impact","name":"Scale-bounce reveal (E2)","what":"A card/element springs in from small with an overshoot bounce.","how":"`tl.fromTo(el,{scale:0.8-0.94,opacity:0},{scale:1,opacity:1,duration:0.32-0.42,ease:'back.out(2)'} )` (back.out(1.6..2.6) tunes bounciness). The default entrance for every device (cards, badges, bubbles, stamps). Seek-safe.","when":"Introducing any hero device or badge. Ubiquitous."},{"id":"impact-shake","group":"motion-impact","name":"Impact shake / jolt (E47)","what":"An element jerks sideways on a hard word ('gone', 'dies', 'part'), either elastic settle or rapid jitter.","how":"Two flavors: settle — `tl.fromTo(el,{x:-10..-14},{x:0,duration:0.5,ease:'elastic.out(1,0.25..0.3)'},T)`; jitter — `tl.to(el,{x:-14,duration:0.05-0.06,yoyo:true,repeat:5-7,ease:'none'},T)`. Applied to cards, headlines, counters. Seek-safe.","when":"Punctuate a hard/negative word or a slam. Common."},{"id":"pulse-scale-yoyo","group":"motion-impact","name":"Pulse (scale yoyo) (E48)","what":"An element breathes up ~5-12% and back once or twice to draw the eye.","how":"`tl.to(el,{scale:1.05-1.14,duration:0.3-0.5,yoyo:true,repeat:1-2,ease:'sine.inOut'},T)`. Applied to CTAs, key numbers, winners, '24/7', meters. Seek-safe.","when":"Emphasize the payoff element right after it appears / on a key word. Ubiquitous."},{"id":"spark-burst-particles","group":"motion-impact","name":"Spark burst (E49)","what":"Small dots shoot radially outward from a success point (booked, winner, confirmed, converted).","how":"JS appends `.spark` divs at the host, then for n in 0..N: `const ang=(2*PI*n)/N, dx=cos(ang)*R, dy=sin(ang)*R; tl.fromTo(s,{opacity:1,x:0,y:0,scale:1},{opacity:0,x:dx,y:dy,scale:0.2,duration:0.5-0.6,ease:'power2.out'},T)`. Radial angles are deterministic (index-based); any jitter uses seeded rnd(). ","when":"Celebration on a win — booking, winner card, confirmation, conversion jump (reels 05,06,07,08,09)."},{"id":"light-sweep-cta","group":"motion-impact","name":"Light sweep across CTA (E43)","what":"A diagonal glint sweeps across the final CTA text like light over glass.","how":"`#sweep` element (absolute, width:35%, skewX(-18deg), linear-gradient transparent→rgba(255,255,255,.35..4)→transparent) inside an overflow:hidden CTA. `tl.fromTo('#sweep',{x:0},{x:900-1500,duration:0.7-0.75,ease:'power2.inOut'},T)`. Usually paired with a CTA pulse. Seek-safe.","when":"Every closing CTA card. Signature finisher."},{"id":"float-bob","group":"motion-impact","name":"Float / bob loop","what":"A lone element (a giant '?') drifts gently up and down.","how":"reel-05 `tl.fromTo('#qm',{opacity:0,scale:0.6},{opacity:0.5,scale:1,ease:'power2.out'},T)` then `tl.to('#qm',{y:-18,duration:1.3,yoyo:true,repeat:1,ease:'sine.inOut'},T2)`. Seek-safe (bounded yoyo).","when":"A single lingering symbol during a reflective line ('a question you never got to answer')."},{"id":"blink-toggle","group":"motion-impact","name":"Blink (INCOMING) (E9)","what":"A label blinks a couple times, like a live 'INCOMING…' status.","how":"`tl.fromTo('#inc',{opacity:.3},{opacity:1,duration:0.4,repeat:2,yoyo:true},T)`. Seek-safe (bounded repeat/yoyo).","when":"Live/incoming status on a phone card."},{"id":"die-dot-slam","group":"motion-impact","name":"Die-dot slam into trough","what":"A red dot drops from above and slams into the bottom of a decay curve.","how":"reel-04 `tl.fromTo('#dieDot',{y:-260,opacity:0},{y:0,opacity:1,duration:0.35,ease:'power3.in'},T)` (power3.in accelerates into the hit). Seek-safe.","when":"'Then it dies' moment on a value chart (reel-04)."},{"id":"drift-away-exodus","group":"motion-impact","name":"Elements drift/bounce away (exodus)","what":"Dots or a card scatter/fly off screen to represent people leaving/bouncing.","how":"Seeded per-element tweens: reel-05 dots `tl.to(d,{opacity:0,x:R(-70,70),y:R(-90,90),scale:0.4,duration:R(0.5,0.9),ease:'power1.in'},start+seededOffset)`; reel-08 `tl.to(d,{opacity:0,x:side*(200+rnd()*160),y:-160-rnd()*120},T+k*0.015)`. Deterministic via seeded PRNG. Seek-safe.","when":"Visitors leaving / bounce beats (reels 05, 08)."},{"id":"reverse-safe-class-toggle","group":"motion-impact","name":"Reverse-safe state toggle via onUpdate","what":"Persistent state changes (FATIGUED stamp, winner highlight) appear on the forward pass and correctly disappear when scrubbing backward.","how":"Instead of a one-shot `.call()`/`.add()` that won't undo on reverse, register `tl.eventCallback('onUpdate',()=>{const t=tl.time(); el.classList.toggle('dead',t>=deadAt); el2.classList.toggle('winner',t>=winAt);})`. Reads the paused timeline's current time every frame so seeking either direction is c","when":"Any latching class/state that must survive frame-by-frame seeking in both directions."},{"id":"seeded-prng-determinism","group":"motion-impact","name":"Seeded PRNG for deterministic randomness","what":"Scatter/particle/dust placements look random but render identically every time (required for frame renders).","how":"A fixed-seed generator replaces Math.random: mulberry32 `function mulberry32(a){return function(){a|=0;a=a+0x6D2B79F5|0;let t=Math.imul(a^a>>>15,1|a);t=t+Math.imul(t^t>>>7,61|t)^t;return((t^t>>>14)>>>0)/4294967296}}` (reels 05,10) or an LCG `__seed=(__seed*1664525+1013904223)>>>0; return __seed/4294","when":"Any effect using randomized positions/offsets — mandatory for seek-safe deterministic renders."},{"id":"strike-through-wipe","group":"kinetic-type","name":"Strike-through wipe on lost value","what":"A horizontal bar wipes across a number or phrase to 'cancel' it (a struck price, 'sale gone', a leaking revenue figure).","how":"A bar element (#leakstrike / #salestrike / #priceStrike) absolutely positioned at ~top:52% over the target, height ~9-12px, background currentColor or --red, transform:scaleX(0);transform-origin:left. JS: tl.fromTo('#strike',{scaleX:0},{scaleX:1,duration:0.4,ease:'power2.inOut'},t). Wrap target in a","when":"Villain/loss beats — killing a price (reel 15), striking lost revenue (reel 12), 'a sale gone' (reel 13)."},{"id":"word-color-flip","group":"kinetic-type","name":"Word / status color flip","what":"A word or status label recolors mid-scene (grey->red for danger, red->accent for recovery).","how":"tl.to(target,{color:'#ff5545',duration:0.3},t) on an inline word span or a status node (#opct, #q5, #scanbadge). Often paired with the beat of a spoken red word. Deterministic single tween.","when":"Turning a metric bad (odds->red) or flipping a mock label from failure to success state."},{"id":"scale-pulse-word","group":"motion-impact","name":"Emphasis scale pulse (yoyo)","what":"A word, price, badge or card gives one quick breathe-out/in scale bump for punch.","how":"tl.to(target,{scale:1.1,duration:0.22,yoyo:true,repeat:1,ease:'sine.inOut'},t) (or back.out(2.4) for a snappier land). Applied to .head words, big numbers, chips, CTA. This is the ubiquitous 'E48 pulse'.","when":"Land the stress on the key spoken word, a revealed number, or the CTA — any accent beat."},{"id":"back-out-bounce-in","group":"motion-impact","name":"Overshoot bounce-in reveal","what":"Cards, chips, flags and badges spring into place with a slight overshoot.","how":"tl.fromTo(el,{scale:0.9,opacity:0,y:16},{scale:1,opacity:1,y:0,duration:0.34-0.42,ease:'back.out(1.6..2.4)'},t). Higher back.out overshoot for smaller poppy elements (flags/checks), gentler for big cards.","when":"The default entrance for any mock UI element, badge, tag, or hero card."},{"id":"cta-light-sweep","group":"kinetic-type","name":"Specular light sweep across CTA","what":"A diagonal gloss band travels across the final 'Book a free AI audit.' headline.","how":"#sweep absolutely positioned inside an overflow:hidden headline: width:35%;height:100%;background:linear-gradient(100deg,transparent,rgba(255,255,255,.35..4),transparent);transform:skewX(-18deg). JS: tl.fromTo('#sweep',{x:0},{x:1400,duration:0.7,ease:'power2.inOut'},t). Often paired with scale-pulse","when":"The closing CTA card of every reel (signature ending)."},{"id":"stacked-cta-list","group":"layout","name":"Stacked multi-line CTA","what":"The CTA is broken into stacked centered lines ('Book a' / 'free' / 'AI audit.') for weight.","how":".stack is flex-column-centered Inter 900 ~150px; each line .ln is position:relative;overflow:hidden holding .w words; the #sweep rides the last line. Words still use per-word-pop at their data-t.","when":"CTA scenes where a single-line headline is too small (reels 14, 17)."},{"id":"typewriter-text","group":"kinetic-type","name":"Typewriter char-by-char reveal","what":"Text types itself into a search bar or chat line one character at a time, often with a blinking caret.","how":"Two seek-safe patterns: (a) helper that schedules per-char tl.call(()=>{el.textContent=text.slice(0,i);},null,t0+dur*i/n) for i=1..n; (b) proxy object tl.to(obj,{i:steps,duration,ease:'none',onUpdate:()=>{el.innerHTML=text.slice(0,Math.round(obj.i))+'<span class=\"cur\">|</span>';}},t0). Caret is a sm","when":"Search-bar queries (reels 16 & 19), AI chat questions/answers being 'live typed' (reel 16)."},{"id":"shutter-flash","group":"cut-transition","name":"White shutter flash","what":"A brief full-frame white flash punctuates a reveal or hard cut.","how":"#flash is a fixed inset:0 white div at z80, opacity:0. JS: tl.to('#flash',{opacity:0.5..0.8,duration:0.05},t).to('#flash',{opacity:0,duration:0.2..0.28,overwrite:'auto'},t+0.05). Higher peak opacity for bigger turns.","when":"The 'turn' beat (problem->fix), a metric slam, a booked-confirmation, or any impact you want to feel like a camera flash"},{"id":"rgb-split-glitch","group":"cut-transition","name":"RGB chromatic-split glitch","what":"A red/blue fringe flashes across the frame to signal disconnection/chaos or a system 'connect' surge.","how":"#rgb fixed inset:0 z79 mix-blend-mode:screen, background:linear-gradient(90deg,rgba(255,0,60,.35),transparent 30%,transparent 70%,rgba(0,160,255,.35)), opacity:0. JS stutters it: tl.to('#rgb',{opacity:0.9,duration:0.05},t).to('#rgb',{opacity:0,duration:0.12},t+0.06) repeated; headline can jitter x i","when":"Chaos/failure beats and the network-powerup surge (reel 20 only)."},{"id":"count-up-number","group":"data-viz","name":"Animated count-up number","what":"A big figure ticks upward — a multiplier (1->21x), recovered revenue ($0->$6,120), leads called (0/200), rank, KPIs.","how":"Animate a proxy: const nv={v:START}; tl.to(nv,{v:END,duration,ease:'power1/2.out',onUpdate:()=>{el.textContent=Math.round(nv.v);}},t). Money uses '$'+Math.round(nv.v).toLocaleString('en-US'). Often followed by a scale-pulse on the number when it lands.","when":"Proof/payoff beats — stat reveals, revenue recovered, volume handled, KPI dashboards."},{"id":"count-down-number","group":"data-viz","name":"Animated count-down number","what":"A rank number counts DOWN dramatically (#30 -> #1) to show a climb.","how":"Same proxy pattern but START>END: tl.to(rankObj,{v:1,duration:1.5,ease:'power2.inOut',onUpdate:()=>{rankEl.textContent=Math.round(rankObj.v);}},t); land with a transform-origin 'center bottom' scale-pulse.","when":"SEO/ranking or position-improvement payoff (reel 19)."},{"id":"meter-fill-drain","group":"data-viz","name":"Horizontal meter fill / drain","what":"A gradient bar collapses or fills to show odds/warmth/readiness, with a synced % label.","how":".meterbar (rounded, bordered) clips a .meterfill (linear-gradient, transform-origin:left). JS: tl.fromTo('#fill',{scaleX:1},{scaleX:0.04,duration:1.5,ease:'power2.in'},t) plus a proxy count for the % label; can desaturate on drain via filter:'saturate(0) brightness(.55)' and swap gradient to red.","when":"'Odds you win' collapse (reel 11), 'hot buyer -> cold' drain (reel 13), 'ready to buy now' fill (reel 17)."},{"id":"countdown-timer-ring","group":"data-viz","name":"Circular countdown / progress ring","what":"A colored arc drains or fills around a big central number (minutes/hours, or hours 'still waiting').","how":"SVG two-circle ring: .ringbg faint + .ringfg (stroke accent, stroke-dasharray = circumference e.g. 942, stroke-linecap round), wrapper svg rotated -90deg. JS animates strokeDashoffset: tl.fromTo('#ring',{strokeDashoffset:0},{strokeDashoffset:800,duration:2,ease:'power1.in'},t) plus a count-up on the","when":"Time-pressure hooks — 5-minute gold window / hours-waiting (reel 11)."},{"id":"clock-arc-fill","group":"data-viz","name":"Clock coverage arc (fraction of day)","what":"An arc fills to ~one-third of a clock to show '8h of 24' coverage.","how":".clockfg SVG circle stroke-dasharray:816;stroke-dashoffset:816;transform:rotate(-90deg). JS: tl.fromTo('#ring',{strokeDashoffset:816},{strokeDashoffset:544,duration:1,ease:'power2.out'},t) (816->544 ~= 1/3). Center number scale-pulses.","when":"Coverage / availability limitation beats (human answers only 8 hours — reel 15)."},{"id":"progress-bar-fill","group":"data-viz","name":"Linear progress bar fill","what":"A thin bar fills left-to-right while a paired counter climbs (outbound dialer 0->200).","how":".dialbar clips .dialfill (gradient, transform-origin:left,scaleX:0). JS: tl.to('#fill',{scaleX:1,duration:1.3,ease:'power2.out'},t) alongside a count-up on the stat label.","when":"Batch/throughput demos — AI calling many leads back (reel 15)."},{"id":"line-chart-draw","group":"data-viz","name":"Rising line-chart self-draw","what":"A traffic line draws itself upward along a curve, ending with a popping endpoint dot.","how":"SVG <path class=\"traf-line\" stroke accent, stroke-dasharray:1;stroke-dashoffset:1>. JS: tl.set('#trafline',{strokeDasharray:LEN,strokeDashoffset:LEN},t); tl.to('#trafline',{strokeDashoffset:0,duration:1.7,ease:'power2.in'},t); then tl.fromTo('#trafdot',{opacity:0,scale:0.4},{opacity:1,scale:1,durati","when":"Growth payoff (traffic rising as rank improves — reel 19)."},{"id":"spark-burst","group":"data-viz","name":"Radial spark particle burst","what":"A ring of small dots shoots outward and fades on a win/success moment.","how":"IIFE builds N .spark divs at a host anchor; for each, ang=(Math.PI*2*n)/N (+ seeded rnd jitter), dx=cos*r, dy=sin*r; tl.fromTo(s,{opacity:1,x:0,y:0,scale:1},{opacity:0,x:dx,y:dy,scale:0.2,duration:0.5-0.6,ease:'power2.out'},t). Seeded rnd() keeps positions deterministic.","when":"Booked/won/recovered/connected celebration beats (reels 11,12,15,16,18,20)."},{"id":"leak-drips","group":"data-viz","name":"Money-leak drip particles","what":"Small red droplets fall away beneath a leaking-revenue number.","how":"IIFE builds droplet divs at seeded left% positions along the number; tl.fromTo(d,{opacity:0.8,y:0},{opacity:0,y:90+rnd()*40,duration:0.5,ease:'power1.in'},t0+n*0.06). Uses --red rounded-bottom shape.","when":"'Revenue walking out the door' loss visualization (reel 12)."},{"id":"count-burn-negative","group":"data-viz","name":"Negative money burn counter","what":"A red figure ticks DOWN into negative (-$0 -> -$2,400) to show wasted spend.","how":"Proxy count-up writing '-$'+Math.round(v).toLocaleString('en-US') into a red .amt; card enters with bounce-in first.","when":"Waste/cost villain beats (paying for new clicks while ignoring old leads — reel 17)."},{"id":"lead-card","group":"ui-mockup","name":"New-lead notification card","what":"A card with an emoji icon tile and 'New lead · HOT · just now' pops in; can later gray to 'COLD · lost'.","how":".lead card (icon .ic radial tile + .txt with .t1/.t2). Enter: tl.fromTo('#lead',{scale:0.9,opacity:0,y:16},{scale:1,opacity:1,y:0,duration:0.4,ease:'back.out(2)'},t). HOT status blinks via tl.fromTo(sub,{opacity:.4},{opacity:1,duration:0.35,repeat:3,yoyo:true},t). Dead state: markup sets opacity/gra","when":"Lead-response hook and the 'lead already gone' loss beat (reel 11)."},{"id":"source-chips-light","group":"ui-mockup","name":"Multi-source chips lighting on","what":"Channel chips (Ads / Forms / DMs / Calls) light up one per spoken source with a colored dot.","how":".chip default dim with a .cd dot; JS adds .on (accent border + glowing dot) and pops: const chipOn=(id,t)=>tl.fromTo(id,{scale:0.9},{scale:1,duration:0.3,ease:'back.out(2.4)',onStart:()=>document.querySelector(id).classList.add('on')},t); one call per source at its word beat.","when":"Enumerating input channels the AI covers (reel 11)."},{"id":"chat-bubble-thread","group":"ui-mockup","name":"SMS/chat bubble thread","what":"Message bubbles (customer left, AI right accent-colored) drop into a thread with meta timestamps.","how":".chat flex-column; .bub.them (card, left, bottom-left-radius 8px) vs .bub.ai (accent bg, right, bold). Each bubble: tl.fromTo(bub,{opacity:0,y:18-24,scale:0.96},{opacity:1,y:0,scale:1,duration:0.3,ease:'back.out(1.5-2)'},t). .meta span for 'auto-sent · 0:03' style caption.","when":"Any conversational demo — AI replying, qualifying, messy back-and-forth (reels 11,13,18)."},{"id":"typing-dots-indicator","group":"ui-mockup","name":"Typing / working dots","what":"Three bouncing dots show the AI 'typing' before its reply pops in.","how":".typing bubble with three <i> dots; the bounce is a CSS @keyframes tdot loop (decorative, tolerated). Seek-timed visibility on tl: tl.fromTo('#typ',{opacity:0},{opacity:1,duration:0.18},t1); tl.to('#typ',{opacity:0,duration:0.14},t2) right before the reply bubble enters.","when":"Selling the 'live' feel just before an AI reply (reel 13)."},{"id":"qualify-checklist","group":"ui-mockup","name":"Qualify checklist rows check-off","what":"Qualification rows ('Budget confirmed', 'Slot picked') slide in and get green checks.","how":".qual with .qrow items each hiding a .chk. Row: tl.fromTo('#q1',{opacity:0,x:-16},{opacity:1,x:0,duration:0.28,ease:'power2.out',onComplete:()=>el.classList.add('done')},t); check: tl.to('#q1 .chk',{opacity:1,duration:0.2},t2).","when":"Showing the AI qualifying a lead (reels 11, 15 task cards)."},{"id":"calendar-fills-itself","group":"ui-mockup","name":"Calendar fills row-by-row","what":"Multiple day rows flip to lime 'full/booked' one per beat, with a spark burst.","how":"Iterate rows: tl.fromTo(id,{backgroundColor:'#0e1016',opacity:0.5},{backgroundColor:'rgba(184,255,44,0.10)',opacity:1,duration:0.3},t0+n*0.28); tl.call to set status textContent='✓ full' + lime color; tl.fromTo scale 0.97->1 back.out. Followed by spark-burst.","when":"Booking payoff montage (reel 18)."},{"id":"time-slot-chips","group":"ui-mockup","name":"Open time-slot offer chips","what":"A list of open time slots docks in; one gets picked and latches to lime 'booked'.","how":".slot rows (opacity:0) dock via tl.fromTo({opacity:0,x:-24},{opacity:1,x:0,duration:0.3,ease:'power2.out'}) staggered per beat. Picked slot has .picked (lime border/bg) and scale-pulses: tl.to('#sl9',{scale:1.05,yoyo:true,repeat:1,ease:'sine.inOut'},t).","when":"Showing availability then selection (reel 18)."},{"id":"reschedule-row-swap","group":"ui-mockup","name":"Self-reschedule text swap","what":"A booked row's status dims to 'moving…' then swaps day/time and latches '✓ moved'.","how":"tl.to('#st',{opacity:0.4,duration:0.2},t); tl.call(()=>{who.textContent=...;day.textContent='FRI 4:30';},[],t+0.5); tl.to('#st',{opacity:1,onStart:()=>{st.textContent='✓ moved';st.style.color='#B8FF2C';}},t+0.6); elastic x settle. Text mutation via tl.call keeps it seek-safe.","when":"'It reschedules itself' beat (reel 18)."},{"id":"reminder-phone-ping","group":"ui-mockup","name":"Reminder phone with ping ripples","what":"A phone card shows a bell, expanding ping rings, and a reminder notification sliding in.","how":".rmphone card + .pingwave with three <i> rings; JS ripples them: rings.forEach((el,n)=>tl.fromTo(el,{opacity:0.6,scale:0.6},{opacity:0,scale:2.2,duration:0.85,ease:'power1.out'},t+n*0.2)). Notif: tl.fromTo('#rmnotif',{opacity:0,y:18,scale:0.96},{opacity:1,y:0,scale:1,duration:0.32,ease:'back.out(1.6","when":"'Sends the reminder' beat (reel 18)."},{"id":"checkout-cart","group":"ui-mockup","name":"E-commerce checkout / cart","what":"A cart card fills with product line-items (emoji thumb, name, price) popping in on beats, with a total and CTA button.","how":".checkout card with .citem rows (opacity:0). Each: tl.fromTo('#ci1',{opacity:0,x:-20,scale:0.96},{opacity:1,x:0,scale:1,duration:0.28,ease:'back.out(1.6)'},t) staggered to cart_add SFX; badge count pulses. Total .ftot in accent.","when":"E-commerce hook (cart filling) — reel 12."},{"id":"abandoned-stamp","group":"ui-mockup","name":"Abandoned / LEFT rubber stamp","what":"A rotated red '✕ LEFT' stamp slams onto a grayed-out cart while the card shakes.","how":".abandoned overlay (rgba scrim) + .stamp (rotated border box). tl.fromTo('#stamp',{opacity:0,scale:1.5,rotation:-24},{opacity:1,scale:1,rotation:-8,duration:0.34,ease:'back.out(2.4)'},t); card jitters via tl.fromTo(x yoyo). Cart pre-grayed with .grayed (grayscale+dim).","when":"Cart-abandon villain beat (reel 12)."},{"id":"channel-reminder-rows","group":"ui-mockup","name":"Multi-channel reminder rows sending","what":"Stacked channel rows (Email / Text / WhatsApp) slide in and each flips to green 'sent ✓'.","how":".chan rows (icon + body + hidden .csent). Row: tl.fromTo('#chan1',{opacity:0,x:-26},{opacity:1,x:0,duration:0.3,ease:'power2.out'},t); sent tag: tl.fromTo('#cs1',{opacity:0,x:-8},{opacity:1,x:0,duration:0.24,ease:'back.out(2)'},t+0.4). Staggered to msg_send SFX.","when":"Omni-channel outreach demos (reels 12 win-back, 17 channel chips)."},{"id":"win-back-offer-card","group":"ui-mockup","name":"Win-back offer card reveal","what":"A personalized 'We miss you' card bounces in and its discount offer button pops after.","how":".winback card with .wtag/.wline/.wsub and a hidden .woffer. Card: tl.fromTo('#wbcard',{opacity:0,y:24,scale:0.96},{...back.out(1.5)},t); offer: tl.fromTo('#wboffer',{opacity:0,scale:0.9},{opacity:1,scale:1,duration:0.34,ease:'back.out(2)'},t2).","when":"Re-engagement of past buyers (reel 12)."},{"id":"unified-inbox-device","group":"ui-mockup","name":"Unified inbox device","what":"A phone-like inbox lists messages across IG/FB/WhatsApp/Website with channel chips and unread counts.","how":".inbox (rounded device, .ib-top header + count badge, .ib-body rows). Each .row has a .ch channel chip (brand gradients: .ig/.fb/.wa/.web), .who/.msg, and .meta (unread pill / flag / stamp / done). Device drops in: tl.fromTo('#ib',{scale:0.9,opacity:0,y:20},{scale:1,opacity:1,y:0,duration:0.34,ease:","when":"Inbox/DM management hero (reel 13)."},{"id":"inbox-badge-count-clear","group":"ui-mockup","name":"Unread badge count clears to zero","what":"The inbox count animates 12 -> 0 and the badge turns from accent to lime 'zero' state.","how":"Proxy: const ic={v:12}; tl.to(ic,{v:0,duration:0.9-1,ease:'power2.out',onUpdate:()=>{el.textContent=Math.round(ic.v); if(ic.v<=0.5) el.classList.add('zero');}},t). .ib-count.zero swaps background to lime.","when":"'One AI clears every inbox' payoff (reel 13)."},{"id":"flag-stamp-in","group":"ui-mockup","name":"Status flag stamp-in (buy/missed/stuck)","what":"A small badge stamps onto a row — '💸 WANTS TO BUY', '⚠ MISSED', '⚑ STUCK'.","how":"Hidden flag (opacity:0). tl.fromTo('#flag',{opacity:0,scale:0.6,x:14},{opacity:1,scale:1,x:0,duration:0.28,ease:'back.out(2.4)'},t) (rotation variant for STUCK). Buyer rows can also glow: tl.to(rows,{boxShadow:'0 0 26px rgba(184,255,44,.35)',stagger:0.08},t). Row bg can shift to red on 'missed'.","when":"Tagging intent/urgency/problem on inbox or CRM rows (reels 13, 14)."},{"id":"channel-icon-cards","group":"ui-mockup","name":"Channel icon cards flip/scatter","what":"Square platform cards (IG/FB/WhatsApp/Website, or Email/Text/WhatsApp) pop in — sometimes flipping in 3D or scattering apart.","how":".chgrid/.chans of .chcard/.chan (icon tile + name). Pop: tl.fromTo(card,{opacity:0,scale:0.5,rotationY:-40},{opacity:1,scale:1,rotationY:0,duration:0.34,ease:'back.out(2)'},t) for a 3D flip; or fromTo with baked x/y/rotation offsets then a later tl.to pushing them outward ('scatter on scattered').","when":"Naming platforms / showing fragmentation then unification (reels 13, 17)."},{"id":"card-scatter-depth","group":"3d","name":"Cards scatter to depth","what":"Four cards, already popped in with baked rotation/offset, fling further apart to feel disordered.","how":"Enter with fromTo where the TO keeps the offset (bakes transform): tl.fromTo('#s3c1',{opacity:0,scale:0.4,x:-30,y:-18,rotation:-6},{opacity:1,scale:1,x:-30,y:-18,rotation:-6,...},t); then tl.to('#s3c1',{x:-96,y:-64,duration:0.6,ease:'power2.out'},t2) to scatter. Each card different vector.","when":"'Your messages are scattered' chaos beat (reel 13)."},{"id":"rotationy-card-flip","group":"3d","name":"3D Y-axis card flip-in","what":"A card swings in around its vertical axis like a turning panel.","how":"tl.fromTo(card,{opacity:0,scale:0.5,rotationY:-40},{opacity:1,scale:1,rotationY:0,duration:0.34,ease:'back.out(2)'},t). GSAP applies the 3D transform; deterministic under seek.","when":"Platform cards revealing per named channel (reel 13 s4)."},{"id":"crm-pipeline-board","group":"ui-mockup","name":"CRM kanban pipeline board","what":"A multi-column board (New/Contacted/Quoted/Won) holds lead cards with tags and counts.","how":".board flex row of .col columns (each .colhead with .cnt count + stacked .lc lead cards). Lead cards carry .tag (hot/warm/won), optional .dust cobweb, .task, .flag. Board can enter scaled/dim; cards animate individually per beat.","when":"CRM/pipeline reel hero and states (reel 14)."},{"id":"card-rot-dust","group":"ui-mockup","name":"Lead cards rot with cobwebs","what":"Pipeline cards gray out and grow cobweb emojis one by one to feel abandoned.","how":"Each card has a hidden .dust (🕸️). Per card: tl.to('#dust1',{opacity:0.9,duration:0.4},t).to('#d1',{filter:'grayscale(1)',opacity:0.34,duration:0.5},t) staggered, synced to a dust_tone SFX. .lc.dead style is the target look.","when":"'Sitting there untouched' decay beat (reel 14)."},{"id":"graveyard-stones","group":"ui-mockup","name":"Graveyard lead 'stones'","what":"Grayed tombstone rows ('🪦 A. Rivera · $85/lead') drop in stacked to represent dead paid leads.","how":".grave stack of .stone rows (pre-grayed grayscale+opacity .4). Stagger drop: tl.fromTo('.grave .stone',{opacity:0,y:26},{opacity:0.4,y:0,duration:0.32,stagger:0.14,ease:'power2.out'},t).","when":"'You paid good money for those leads' loss framing (reel 14)."},{"id":"tag-pop","group":"ui-mockup","name":"Lead tag pop (HOT/WARM)","what":"A colored qualification tag (🔥 HOT / ☆ WARM) pops onto a lead card.","how":"Hidden tag: tl.fromTo('#tag1',{scale:0,opacity:0},{scale:1,opacity:1,duration:0.34,ease:'back.out(2.6)'},t), synced to a tag_pop SFX. .tag.hot/.warm/.won carry the semantic colors.","when":"'AI tags every lead' demo (reel 14)."},{"id":"card-column-slide","group":"ui-mockup","name":"Card slides between kanban columns","what":"A lead card whips from the New column into Contacted while both column counts flip.","how":"tl.fromTo('#mvcard',{x:-260,opacity:0},{x:0,opacity:1,duration:0.5,ease:'power3.out'},t) (whip slide); counts flip via tl.fromTo('#c10a',{scale:1.4,color:ACCENT},{scale:1,color:'#8a8f99',duration:0.4},t).","when":"'Moves it through the stages' automation demo (reel 14)."},{"id":"checklist-write-on","group":"ui-mockup","name":"Follow-up task list writes on","what":"Blue task rows ('✓ Call A. Rivera — today 2pm') slide in one per beat.","how":".task rows (opacity:0): tl.fromTo('#tk1',{opacity:0,x:-24},{opacity:1,x:0,duration:0.3,ease:'power2.out'},t) staggered ~0.4s apart.","when":"'Writes the follow-up tasks' beat (reel 14); same pattern as qualify/task cards."},{"id":"stuck-flag","group":"ui-mockup","name":"Stuck-deal red flag","what":"A red '⚑ STUCK' flag stamps onto a stalled deal card with a shake and flash.","how":"tl.fromTo('#stuckflag',{scale:0,opacity:0,rotation:-12},{scale:1,opacity:1,rotation:0,duration:0.36,ease:'back.out(2.8)'},t); card elastic x-settle; shutter-flash at same beat.","when":"'Flags the deals that are stuck' beat (reel 14)."},{"id":"kpi-dashboard-tiles","group":"ui-mockup","name":"KPI dashboard tiles count up","what":"A row of stat tiles (Active / Moved today / Flagged, or Closed / Of goal) reveals and numbers count up.","how":".dash > .kpis of .kpi (big .v value + .l label, colored .v.b/.ok/.rd). Tiles stagger in: tl.fromTo('.dash .kpi',{y:24,opacity:0},{y:0,opacity:1,duration:0.36,stagger:0.1,ease:'back.out(1.8)'},t); each value count-up via its own proxy. Villain version stays at $0/0%.","when":"Visibility payoff ('shows you exactly what's happening') or the villain 'month closes short' (reel 14)."},{"id":"price-anchor-cards","group":"ui-mockup","name":"Price-anchor vs comparison cards","what":"A pricey 'human' card sits beside a struck price and an accent 'AI' card counting up to a fraction.","how":".anchor with .pricecard.old (struck via #priceStrike) and .pricecard.new (accent gradient) separated by a .vs. Cards bounce in; old price gets strike-through-wipe; new price count-ups ($0->$99) then scale-pulses.","when":"Cost-comparison hook and payoff (reel 15 receptionist vs AI voice agent)."},{"id":"voice-waveform","group":"ui-mockup","name":"Live voice waveform bars","what":"A row of vertical bars oscillates like a live voice while a status dot pulses.","how":"Build N span bars once (JS loop). Drive heights with a proxy over the paused tl: tl.to(waveProxy,{t:1,duration:3.6,ease:'none',onUpdate:()=>{const p=waveProxy.t*40; bars.forEach((b,i)=>{b.style.height=(30+Math.abs(Math.sin(p*0.9+i*0.55))*Math.abs(Math.sin(p*0.3+i*0.2))*110).toFixed(1)+'px';});}},t).","when":"AI voice-agent 'answering live' demo (reel 15)."},{"id":"outbound-dialer-card","group":"ui-mockup","name":"Outbound dialer card","what":"A dialer card with pulsing call rings, a progress bar, and a 'called back 0/200' counter.","how":".dialer with .dialrings (CSS @keyframes ring loop — decorative), .dialbar>.dialfill (progress-bar-fill) and .dialstat counter. Card bounces in; fill + count-up run together. A disconnected/failure variant is dimmed (opacity .4) and jitters.","when":"'It calls your leads back' outbound demo, and the human 'can't call 200 back' villain (reel 15)."},{"id":"ai-chat-search-mock","group":"ui-mockup","name":"AI assistant chat window","what":"A browser-chrome-style AI card (traffic-light dots + '✦ AI Assistant') shows a typed question and a one-name answer.","how":".ai card with a .bar (colored .dot r/y/g + .brand) and .body of .qrow rows (avatar .ava.you/.bot + .qtext). Question/answer revealed via typewriter-text; card bounces in. Answer can contain a .naming.bad (red) or .naming.good (lime) brand token.","when":"GEO / AI-search visibility reel — how customers ask AI who's best (reel 16)."},{"id":"search-bar-type","group":"ui-mockup","name":"Search bar with typed query","what":"A pill/Google-style search bar types out a query ('best plumber near me') with a caret.","how":"Rounded .searchbar (or Google .serpbar with a blue 'G') containing a .txt/.q target; typewriter-text drives it, then tl.call swaps in a trailing <span class=\"cursor/cur\"> caret. Synced to a keyboard SFX.","when":"Establishing a search intent (reels 16 hook, 19 keyword research)."},{"id":"naming-badge-flip","group":"ui-mockup","name":"Recommended-name badge (rival vs you)","what":"The AI's answer highlights a name — red 'RivalCo →' on the fail beat, lime 'YOU ✓' on the win beat.","how":".naming.bad (red pill) / .naming.good (lime pill) inside the answer. Pop: tl.fromTo('#badname',{scale:0.7,opacity:0},{scale:1,opacity:1,duration:0.34,ease:'back.out(2)'},t); win version adds scale-pulse + flash + spark-burst.","when":"The lose-to-competitor vs get-recommended contrast (reel 16)."},{"id":"authority-trust-chips","group":"ui-mockup","name":"Authority / trust checklist chips","what":"Chips ('✓ Authority', '✓ Schema markup', 'understand', 'trust') dock in one per beat.","how":".chips wrap of .chip (opacity:0, .ck check mark). Iterate: chips.forEach((c,idx)=>tl.fromTo(c,{opacity:0,y:24,scale:0.9},{opacity:1,y:0,scale:1,duration:0.3,ease:'back.out(1.6)'},t0+idx*STEP)). Some land with scale-pulse.","when":"'We build the authority and content' solution montage (reel 16)."},{"id":"serp-results-list","group":"ui-mockup","name":"Google SERP results list","what":"A Google-style results list with ranked rows; the 'you' row sits buried at #30 with a red 'PAGE 3' tag.","how":".serp with a .serpbar (search bar) and .serplist of .serprow (rank .rk + .txt title/url). .serprow.you gets accent border/color. Buried row: tl.fromTo('#buriedrow',{opacity:0,y:26},{opacity:1,y:0,duration:0.4,ease:'power2.out'},t); .pagetag.bad fades in; a small sink-shake yoyo on the row.","when":"SEO reel — showing where the business ranks (reel 19)."},{"id":"thin-page-card","group":"ui-mockup","name":"Thin-content page card + stamp","what":"A near-empty page card draws two skeleton lines then slaps a red 'THIN CONTENT' stamp.","how":".thincard with .thinline bars (transform-origin:left) drawn via tl.fromTo({scaleX:0},{scaleX:1,duration:0.3-0.4,ease:'power2.out'}) staggered; then shutter-flash + tl.fromTo('#thinstamp',{opacity:0,scale:0.7},{opacity:1,scale:1,duration:0.35,ease:'back.out(2.2)'},t).","when":"'Your pages are thin' diagnosis beat (reel 19)."},{"id":"fix-chips-dock","group":"ui-mockup","name":"Fix chips dock with OK checks","what":"Solution chips ('📄 Service pages', '📍 Local SEO') slide in and flip to green '✓ Built / ✓ Fixed'.","how":".fixchip rows (opacity:0) dock: tl.fromTo('#fx1',{opacity:0,x:-30},{opacity:1,x:0,duration:0.4,ease:'back.out(1.6)'},t); the hidden .ok flips in: tl.fromTo('#fx1ok',{opacity:0,scale:0.6},{opacity:1,scale:1,duration:0.3,ease:'back.out(2.2)'},t2).","when":"'It builds strong pages, fixes your local SEO' solution montage (reel 19)."},{"id":"drip-sequence-rail","group":"ui-mockup","name":"Email/drip nurture rail","what":"Day-labeled message rows (DAY 1/3/7 with channel emoji + 'sent') stack up as a sequence.","how":".seq stack of .drip rows (opacity:0): tl.fromTo('#d1a',{opacity:0,y:24,scale:0.94},{opacity:1,y:0,scale:1,duration:0.3,ease:'back.out(2)'},t) synced to a drip SFX. Each row: .day (accent) + .ch emoji + .msg + .st status.","when":"Nurture/follow-up sequence hook and the working demo (reel 17)."},{"id":"sequence-stopped-row","group":"ui-mockup","name":"Sequence stalls / STOPPED","what":"A DAY 7 row goes red-tinted with a 'STOPPED' badge and grays out to show follow-up dying.","how":".drip.stopped (opacity/grayscale). tl.fromTo('#d2c',{backgroundColor:'#14161c',borderColor:'#2a2f3a'},{backgroundColor:'#1c1113',borderColor:'#5a2a2a',duration:0.3},t); STOPPED badge: tl.fromTo('#d2stop',{scale:0.7,opacity:0},{scale:1,opacity:1,...back.out(2.4)},t); elastic x-shake.","when":"'You quit at day three / you stop following up' villain beats (reel 17)."},{"id":"dead-lead-revive","group":"ui-mockup","name":"Dead lead list revives grey->gold","what":"Grey 'DEAD' lead rows warm up — dot glows gold, name brightens, DEAD tag fades, '✓ reactivated' appears.","how":"revive() helper on a row at time ta: tl.to(dot,{backgroundColor:'#FFC24B',boxShadow:'0 0 16px rgba(255,194,75,.8)',duration:0.3},ta); tl.to(nm,{color:'#F4F1EA'},ta); tl.to(tag,{opacity:0,duration:0.2},ta); tl.fromTo(row,{borderColor:'#2a2f3a'},{borderColor:'#FFC24B'},ta); tl.fromTo(chk,{opacity:0,x:","when":"'Wakes up your old leads' reactivation payoff (reel 17)."},{"id":"rival-generic-card","group":"ui-mockup","name":"Rival 'won them' card","what":"A card names the competitor who kept in touch and won the customer, with a green '✓ Won them'.","how":".rival card (name + green .tag). Bounce in: tl.fromTo('#rival6',{scale:0.9,opacity:0,y:20},{scale:1,opacity:1,y:0,duration:0.42,ease:'back.out(2)'},t).","when":"'They buy from whoever stayed in touch' loss beat (reel 17)."},{"id":"big-word-glow","group":"kinetic-type","name":"Giant glowing key word","what":"A single oversized gold word ('buried gold.') bursts in with a glow and pulse.","how":".bigword Inter 900 ~170px, color gold with text-shadow glow. tl.fromTo('#goldword',{scale:0.8,opacity:0},{scale:1,opacity:1,duration:0.4,ease:'back.out(2.4)'},t).to('#goldword',{scale:1.06,yoyo:true,repeat:1,ease:'sine.inOut'},t2); preceded by shutter-flash.","when":"One-word emphasis payoff (reel 17 'buried gold')."},{"id":"tool-node-network-hero","group":"ui-mockup","name":"Scattered tool nodes with 'YOU' glue","what":"Six app nodes sit tilted and disconnected around a central 'YOU · THE GLUE' orb that anxiously breathes.","how":".hero holds absolutely-positioned .node tiles (each rotated in CSS) + a central #you orb. Nodes pop in staggered with bounce then idle-drift: tl.fromTo(el,{scale:0.4,opacity:0},{scale:1,opacity:1,...back.out(2.2)},t); tl.to(el,{rotation:base±3,duration:0.9,yoyo:true,repeat:3,ease:'sine.inOut'},t+0.3","when":"Full-AIOS reel chaos hero — you holding many tools together (reel 20)."},{"id":"connection-network-draw","group":"data-viz","name":"Connection network self-draws + pulses","what":"On the turn, glowing blue lines draw from each tool node into the core, light pulses travel inward, and nodes light up.","how":"SVG #net7 paths (stroke blue, drop-shadow glow, dasharray:1/offset:1). Per path: len=el.getTotalLength(); tl.set(el,{strokeDasharray:len,strokeDashoffset:len},t0); tl.to(el,{strokeDashoffset:0,duration:0.5,ease:'power2.inOut'},t0+k*0.09). Nodes swap to .lit class via tl.set(id,{className:'node lit'}","when":"'Imagine one AI system' unification turn (reel 20)."},{"id":"unified-dashboard-tiles","group":"ui-mockup","name":"Unified AIOS dashboard tiles light up","what":"A dashboard of module tiles (Leads/Sales/Appointments/Reviews/Reports/Everything) lights one per spoken item with checks and spark bursts.","how":".dash card (blue-glow border) with a 2-col .grid of .tile (default opacity .32). Per tile at its beat: tl.set(t,{className:'tile on'},at); tl.fromTo(t,{scale:0.96},{scale:1,...back.out(2)},at); tl.fromTo(check,{opacity:0,scale:0.4},{opacity:1,scale:1,...back.out(2.4)},at+0.05); plus a small spark-bu","when":"The everything-in-one payoff montage (reel 20)."},{"id":"status-dot-live","group":"ui-mockup","name":"Live status dot / LIVE badge","what":"A small glowing dot (with 'live'/'LIVE' label) breathes to signal an active/online system.","how":"A round dot with box-shadow glow; pulsed via tl.to('#dot',{opacity:0.4,duration:0.5,yoyo:true,repeat:N,ease:'sine.inOut'},t). Used in voice card header, dashboard header (.ddot), AI-search brand chip.","when":"Any 'this is running now' device header (reels 15,16,20)."},{"id":"film-grain","group":"ambience","name":"Film grain overlay","what":"A subtle static grain texture sits over the whole frame for a filmic feel.","how":"#grain fixed inset:0 z70 opacity .06 mix-blend-mode:overlay, background is an inline SVG feTurbulence fractalNoise data-URI. Static by default; reel 17 adds a slow parallax via tl.to('#grain',{backgroundPositionX:'60px',backgroundPositionY:'40px',duration:31,ease:'none'},0).","when":"Always on — the base texture layer of every reel."},{"id":"dot-grid-parallax","group":"ambience","name":"Parallax dot-grid backdrop","what":"A faint lime dot grid drifts slowly behind everything for tech-y depth.","how":"#dotgrid absolute inset:-10% z0 opacity .10, background radial-gradient dot pattern with background-size 46px. Drift: tl.fromTo('#dotgrid',{yPercent:-2,scale:1.06},{yPercent:2,scale:1,duration:FULL,ease:'none'},0).","when":"GEO/AI-search reel backdrop (reel 16); optional depth layer."},{"id":"background-rotation-system","group":"layout","name":"Per-scene background rotation","what":"Scenes flip between black, white/cream, the reel's accent color, (and deep-blue in r20) beat to beat for rhythm.","how":"Each .scene carries a bg class: .bg-k (black radial), .bg-w (cream radial), .bg-o (accent radial), .bg-b (deep blue, r20 only). No JS — it is authored per section. Text color and per-word tint classes (.k on light, .wt/.o on dark) adapt to the background.","when":"Every reel — the macro visual pacing device; alternate to keep energy up and to color-code problem (dark/red) vs solutio"},{"id":"type-voice-system","group":"layout","name":"Per-reel type-voice selection","what":"Each reel commits to one headline personality — chunky Inter, technical Space Mono, or editorial Instrument Serif.","how":".head font-family is set per reel: Inter 800/900 (giant-sans), Space Mono 700 (mono-technical), or Instrument Serif (editorial). Space Mono is the shared font inside all device mockups/labels regardless of headline voice. .head.sm/.xl/.tiny modifiers scale within the voice.","when":"Set once per reel to match subject tone (mono for tech/search topics, serif for the SEO editorial reel, Inter for punchy"},{"id":"centered-scene-layout","group":"layout","name":"Centered stacked scene layout","what":"Copy and one hero device stack vertically, centered, with generous gaps and side padding.","how":".scene is display:flex;flex-direction:column;align-items:center;justify-content:center;gap:52-56px;padding:0 90-96px;text-align:center. Captions can be pinned instead with position:absolute;bottom:Npx when the hero fills the frame (reels 16,20).","when":"Universal scene skeleton — one idea + one visual per scene."},{"id":"glow-pulse-boxshadow","group":"motion-impact","name":"Glow pulse (box-shadow yoyo)","what":"A card or button briefly blooms an accent glow to draw attention after it lands.","how":"tl.fromTo(el,{boxShadow:'0 0 0 rgba(255,107,0,0)'},{boxShadow:'0 0 30px rgba(255,107,0,0.5)',duration:0.4,yoyo:true,repeat:1},t) (or a tl.to to a lime glow on the dashboard). Purely GSAP box-shadow tween, seek-safe.","when":"Emphasize a detected/active state (reel 12 AI-detected button, reel 20 dashboard 'all connected')."},{"id":"scene-beat-cut","group":"cut-transition","name":"Scene beat-cut (autoAlpha in/out)","what":"Each script beat is a full-screen scene that snaps on at data-in and off at data-out with hard cuts on the voice rhythm.","how":"Every beat is a `.scene{position:absolute;inset:0;opacity:0;visibility:hidden}` carrying data-in/data-out in seconds. In the scene loop: `tl.set(sc,{autoAlpha:1},dataIn)` then `tl.set(sc,{autoAlpha:0},dataOut)`. autoAlpha toggles both opacity and visibility so hidden scenes never intercept. This is ","when":"Universal skeleton for any multi-beat narrated reel; one scene per spoken sentence/clause."},{"id":"scene-entry-zoom-blur","group":"cut-transition","name":"Alternating zoom+deblur scene entry","what":"As each scene appears it snaps from a slight scale with motion blur to crisp, alternating a zoom-in feel on even scenes and a zoom-out feel on odd scenes.","how":"In the scene loop, keyed on index parity: even -> `tl.fromTo(sc,{scale:1.05,filter:'blur(9px)'},{scale:1,filter:'blur(0px)',duration:0.22,ease:'power2.out',overwrite:'auto'},dataIn)`, odd -> `{scale:0.95,filter:'blur(7px)'}` with ease power3.out. Placed exactly at dataIn so the deblur reads as a pun","when":"Default life-on-entry for every scene; gives energy to hard cuts without a real transition."},{"id":"per-word-kinetic-reveal","group":"kinetic-type","name":"Per-word rise-and-fade reveal","what":"Words pop up one at a time from slightly below, fading in on the exact beat they are spoken.","how":"Core shared device: `document.querySelectorAll('.w[data-t]').forEach(w=>{const t=parseFloat(w.dataset.t);tl.fromTo(w,{opacity:0,yPercent:72},{opacity:1,yPercent:0,duration:0.2,ease:'power3.out'},t);})`. `.w{display:inline-block;will-change:transform,opacity}`. yPercent varies 60-80 across reels. dat","when":"Every headline/caption in every reel; the primary kinetic-typography engine."},{"id":"per-word-reveal-blur-variant","group":"kinetic-type","name":"Per-word reveal with motion blur","what":"Same rise-and-fade word reveal but each word also sharpens from a blur, giving a softer, filmic pop.","how":"Reel 21b variant: `tl.fromTo(w,{opacity:0,yPercent:80,filter:'blur(4px)'},{opacity:1,yPercent:0,filter:'blur(0px)',duration:0.2,ease:'power3.out'},t)`. Adds filter blur to the base per-word reveal.","when":"When the reel style is richer/asset-heavy and you want type to feel more cinematic than snappy."},{"id":"word-scale-punch","group":"kinetic-type","name":"Headline scale-punch on beat","what":"A key headline snaps up from slightly small to full size with a springy overshoot on the emphasized word.","how":"`tl.fromTo('<sel> .head.xl',{scale:0.85},{scale:1,duration:0.3-0.4,ease:'back.out(2 to 2.2)'},beatTime)`. Targeted by scene attribute selector e.g. `.bg-o[data-in=\"2.136\"] .head.xl`. Used on punchline words (SAME JOB, 21x, ONE ANSWER, YOU DON'T EXIST, OWNER, THEY ALREADY ARE).","when":"The single biggest word of a beat — reframes, stat reveals, one-word payoffs."},{"id":"money-count-up-odometer","group":"data-viz","name":"Money / number count-up odometer","what":"A big number rolls up from $0 to its final value like an odometer, then lands.","how":"Tween a proxy: `const m={v:0}; tl.to(m,{v:52000,duration:1.3-2.1,ease:'power1.out',onUpdate:()=>{el.textContent='$'+Math.round(m.v).toLocaleString('en-US');}},startTime)`. Deterministic under scrub because value is a pure function of timeline position. Seen: reel21 $52,000; reel26 $2,000; reel27 $14","when":"Cost/loss/recovered-revenue reveals; any 'the number' beat that should feel like it's adding up live."},{"id":"giant-money-slam","group":"motion-impact","name":"Money slam scale-pop + white flash","what":"When the counted number lands it kicks slightly larger then elastic-settles while the whole frame flashes white for a frame.","how":"On land: `tl.to('.money',{scale:1.06,duration:0.14,ease:'power3.out'},t).to('.money',{scale:1,duration:0.5,ease:'elastic.out(1,0.4)'},t+0.14)` combined with `tl.to('#flash',{opacity:0.5,duration:0.05},t).to('#flash',{opacity:0,duration:0.25},t+0.06)`. `.money` is Inter 900 ~210-300px.","when":"The impact frame of a money count-up or any big-number payoff."},{"id":"big-number-slam-pop","group":"data-viz","name":"Big-number pop-in slam","what":"A huge stat (21x, 14, 11) bursts in from small+transparent with a spring.","how":"`tl.fromTo('#x21',{scale:0.5,opacity:0},{scale:1,opacity:1,duration:0.4,ease:'back.out(2.2)'},t)` often paired with a #flash punch. `.big21{font-size:300px;color:var(--orange);text-shadow:0 0 60px rgba(255,107,0,.35)}` / `.bignum{font-size:220px}`.","when":"Single hero statistic reveals (multipliers, counts, scores)."},{"id":"strike-through-bar","group":"kinetic-type","name":"Animated strike-through bar","what":"A colored bar wipes left-to-right across a word or phrase to cross it out (asking HARDER, HALF your calls, BAD DAY, ten blue links, GONE).","how":"Absolutely-position a `.strike{left:-6%;width:112%;height:11-12px;background:var(--red);transform-origin:left;transform:scaleX(0);box-shadow:0 0 20px}` inside a `position:relative` head, then `tl.to('#strike',{scaleX:1,duration:0.35-0.5,ease:'power2.inOut'},t)`. reel21 verdict uses #verdictstrike; r","when":"Negating/canceling a phrase, or marking a wrong assumption as crossed out."},{"id":"scribble-underline-draw","group":"kinetic-type","name":"Hand-drawn scribble underline (SVG draw)","what":"A wobbly hand-drawn line draws itself under a word.","how":"Inline SVG path under the word `.scribble path{stroke:var(--orange);stroke-width:9;stroke-linecap:round;stroke-dasharray:1;stroke-dashoffset:1}`; animate `tl.set('#scr1',{strokeDasharray:320,strokeDashoffset:320},t); tl.to('#scr1',{strokeDashoffset:0,duration:0.5,ease:'power1.inOut'},t+0.16)`. Path ","when":"Hook emphasis (reel21 'desks.'); adds a hand-made, human accent."},{"id":"underline-bar-draw","group":"kinetic-type","name":"Solid underline bar draw","what":"A clean colored underline sweeps out beneath a hero word.","how":"`.underline{height:12px;border-radius:6px;background:var(--lime);transform:scaleX(0);transform-origin:left center}` then `tl.fromTo('#u2',{scaleX:0},{scaleX:1,duration:0.4,ease:'power2.out'},t)` (pilot 'leak.'). Same scaleX-from-left mechanic as strike but decorative not negating.","when":"Emphasize/underscore a keyword positively (brand-color underline)."},{"id":"gradient-noise-text-fill","group":"kinetic-type","name":"Textured gradient text fill (WAITING / SILENCE)","what":"A giant word is filled with a grainy orange (or red) gradient instead of flat color, like spray-painted metal.","how":"`.tex{background-image:linear-gradient(135deg,#ff8f3c,#ff6b00 55%,#c95200), url(data:image/svg+xml fractalNoise);background-size:cover;-webkit-background-clip:text;background-clip:text;color:transparent}`. The word still animates via the normal per-word reveal; the fill is static CSS (seek-safe). Re","when":"One dramatized emotional keyword per reel (the villain word)."},{"id":"chromatic-aberration-text","group":"kinetic-type","name":"RGB-split (chromatic aberration) headline","what":"Big poster words carry a red/cyan edge fringe like a mis-registered print.","how":"`.ab{text-shadow:2.4px 0 rgba(255,30,70,.75),-2.4px 0 rgba(0,215,255,.72)}` applied to Archivo Black heads (reel 21b). Purely static offset shadow — combine with per-word reveal for motion.","when":"Retro/print-collage aesthetic reels; hook and reframe posters."},{"id":"marker-highlight-word","group":"kinetic-type","name":"Marker-highlight word box","what":"A word sits inside a solid orange (or green) highlighter rectangle.","how":"`.mark{background:var(--orange);color:#160a00;padding:.02em .16em;border-radius:4px;box-decoration-break:clone}` (green variant `.mark.g`). Wrap the word span; it reveals with the normal per-word tween. Reel 21b 'LUNCH','SICK','VOID','every','BOOKING'.","when":"Punch a single noun inside a sentence without changing font size."},{"id":"stamp-rotate-pop","group":"kinetic-type","name":"Rubber-stamp rotate pop","what":"A tilted outlined stamp ('The Myth') slams on rotated and springs to its resting tilt.","how":"`.stamp{border:3px solid var(--red);color:var(--red);padding:12px 26px;border-radius:12px;transform:rotate(-7deg)}` then `tl.fromTo('#mythstamp',{opacity:0,scale:0.4,rotation:-30},{opacity:1,scale:1,rotation:-7,duration:0.4,ease:'back.out(2.2)'},t)`.","when":"Labeling a claim as 'the myth', 'the truth', a verdict tag."},{"id":"steal-this-tag-pop","group":"kinetic-type","name":"'Steal this' dashed tag pop","what":"A dashed-border mono tag (★ steal this ★ / test this yourself) pops in slightly rotated on the orange give-value beat.","how":"`.steal{border:2.5px dashed #160a00;border-radius:22px;padding:12px 26px;font-family:Space Mono;letter-spacing:.14em;color:#160a00}` then `tl.fromTo('#stealtag',{scale:0.4,rotation:-12,opacity:0},{scale:1,rotation:-4,opacity:1,duration:0.4,ease:'back.out(2.2)'},t)`. Always sits on a .bg-o scene.","when":"The 'even if you never hire us / free value' beat that builds trust before the sell."},{"id":"white-flash-hit","group":"motion-impact","name":"White flash impact","what":"The whole frame blinks white for a couple frames to accent an impact.","how":"Full-screen `#flash{inset:0;background:#fff;opacity:0;z-index:80}` then `tl.to('#flash',{opacity:0.3-0.5,duration:0.05},t).to('#flash',{opacity:0,duration:0.25},t+0.06)`. Scored with a braam/boom SFX at the same data-start.","when":"Number slams, punchline reveals, 'YOU DON'T EXIST' style hits."},{"id":"rgb-split-cut-flash","group":"cut-transition","name":"RGB-split flash on cut","what":"On each scene cut a red and cyan wash briefly offset and vanish, giving a glitchy transition seam.","how":"Reel 21b: full-screen `#rgbR{background:rgba(255,30,60,.5);mix-blend-mode:screen}` and `#rgbC{background:rgba(0,220,255,.5)}` opacity 0. In scene loop: `tl.set('#rgbR',{opacity:0.5,x:6},i).set('#rgbC',{opacity:0.5,x:-6},i).to('#rgbR',{opacity:0,x:0,duration:0.16,ease:'power2.out'},i).to('#rgbC',{opa","when":"Glitch/collage-styled reels wanting a per-cut accent."},{"id":"stagewrap-rotate-settle","group":"cut-transition","name":"Stage rotate-settle entry","what":"The whole content block of a scene tips in with a tiny rotation and settles level as it deblurs.","how":"Reel 21b wraps content in `.stagewrap` and does `const dir=idx%2===0?1:-1; tl.fromTo(wrap,{scale:1.04,rotation:0.8*dir,filter:'blur(6px)'},{scale:1,rotation:0,filter:'blur(0px)',duration:0.26,ease:'power3.out'},i)`.","when":"Adds handheld/organic feel; pairs with collage corner cards."},{"id":"comparison-split-vs","group":"layout","name":"Persistent split-screen face-off","what":"A two-column left(red)/right(blue-lime) split with a center divider and a VS badge; one side is lit while the other is grayed, then they swap for the reveal.","how":"A persistent layer behind captions: `.split{position:absolute;inset:0;display:flex} .col.left/.right` gradient columns with `.price`,`.chip` stacks. Shown/hidden with `tl.set('#splitLayer',{autoAlpha:1},t)`; the inactive column is dimmed via `tl.set('#col.right',{filter:'grayscale(0.85) brightness(0","when":"Direct A-vs-B comparisons (human vs AI, cost vs value)."},{"id":"vs-badge-pop","group":"layout","name":"Circular VS badge pop","what":"A round 'VS' medallion springs into the center seam of a split when the second contender appears.","how":"`.vs{position:absolute;top:88px;left:50%;transform:translateX(-50%);width:118px;height:118px;border-radius:50%;background:radial-gradient(...);border:3px solid #3a4152}` then `tl.fromTo('#vsBadge',{autoAlpha:0,scale:0.5},{autoAlpha:1,scale:1,duration:0.4,ease:'back.out(2.2)'},t)`.","when":"Marking the moment a comparison becomes a head-to-head."},{"id":"caption-band-over-layer","group":"layout","name":"Caption band over a live layer","what":"Kinetic captions sit at the lower third over the split, on a dark gradient scrim so text stays legible.","how":"`.cap{position:absolute;left:0;right:0;bottom:150px;z-index:9}` for the text and a separate `.capbg{bottom:0;height:520px;background:linear-gradient(180deg,transparent,rgba(0,0,0,.72) 60%)}` toggled with `tl.set('#capbg',{opacity:1},t)`. Captions themselves use the standard .w reveal.","when":"Any time narrated captions must overlay a busy graphic layer."},{"id":"chip-cascade-stack","group":"motion-impact","name":"Pro/con chip cascade","what":"Labeled chips (🍔 Takes lunch, ✓ Every call 1st ring) drop in one per beat, stacking down a column.","how":"`.chip{opacity:0;transform:translateY(24px)}` then per chip `tl.fromTo('#cL1',{opacity:0,y:24},{opacity:1,y:0,duration:0.32,ease:'back.out(1.8)'},beat)` synced to voice cut times; landed chips get a scale pulse `tl.to(id,{scale:1.04,...},t+0.32).to(id,{scale:1,...},t+0.48)`.","when":"Listing accumulating problems or benefits in a comparison column."},{"id":"scale-pulse-land","group":"motion-impact","name":"Scale-pulse on land","what":"An element that just appeared gives a small confident bounce (grows 4% then settles).","how":"`tl.to(id,{scale:1.04,duration:0.16,ease:'power2.out',overwrite:'auto'},t).to(id,{scale:1,duration:0.3,ease:'sine.out',overwrite:'auto'},t+0.16)`. Reused for pros ticking in and CTA buttons.","when":"Confirm a positive item landed (checks, wins, buttons)."},{"id":"shake-elastic-emphasis","group":"motion-impact","name":"Elastic shake emphasis","what":"A word or card jolts sideways and wobbles back to rest on a hard word ('void', 'nothing', 'GONE').","how":"`tl.fromTo(target,{x:-10},{x:0,duration:0.5,ease:'elastic.out(1,0.25)'},t)` (or `.to(target,{x:-10,...})`). Applied to chips, verdict cards, and headline elements.","when":"Punctuate an impactful negative word or a slam."},{"id":"light-sweep-shine","group":"motion-impact","name":"Light-sweep glare across CTA","what":"A diagonal band of light glides across the CTA text like a shine.","how":"`#sweep{position:absolute;top:0;left:-40%;width:35%;height:100%;background:linear-gradient(100deg,transparent,rgba(255,255,255,.4),transparent);transform:skewX(-18deg)}` inside an `overflow:hidden` CTA, then `tl.fromTo('#sweep',{x:0},{x:1500,duration:0.8,ease:'power2.inOut'},t)`.","when":"CTA reveals to add a premium 'glint'."},{"id":"cta-button-pulse","group":"motion-impact","name":"CTA button pop + heartbeat pulse","what":"The pill CTA button pops up then gently pulses to draw the tap.","how":"`.cta-btn{background:linear-gradient(90deg,#ff8f3c,var(--orange));border-radius:54px;box-shadow:0 20px 60px rgba(255,107,0,.35)}` then `tl.fromTo('#ctabtn',{opacity:0,y:30,scale:0.9},{opacity:1,y:0,scale:1,duration:0.4,ease:'back.out(1.8)'},t).to('#ctabtn',{scale:1.04,duration:0.4,yoyo:true,repeat:1","when":"Final CTA of any reel."},{"id":"whatsapp-chat-window","group":"ui-mockup","name":"Messaging app chat window","what":"A realistic dark chat card with a header (avatar, name, ● online status) and message bubbles.","how":"`.chat{background:#14161c;border-radius:36-40px;box-shadow:0 40px 100px} .chat .bar` header with `.av` circle avatar + `.who` name/status, `.body{display:flex;flex-direction:column;gap;min-height;justify-content:flex-end}`. Bubbles `.msg.in` (left, gray) vs `.msg.out` (right, orange/green gradient) ","when":"Any 'someone texts your business' / conversation proof beat."},{"id":"chat-bubble-cascade","group":"ui-mockup","name":"Chat bubble pop cascade","what":"Message bubbles pop in one after another to play out a mini conversation (reply → price → booked ✓).","how":"Per bubble `tl.fromTo('#c1',{opacity:0,scale:0.6,y:20},{opacity:1,scale:1,y:0,duration:0.3,ease:'back.out(1.9)'},beat)` staggered by voice beats. Inner text uses .w reveal so the words appear with the bubble.","when":"Showing an AI agent resolving a lead across a few quick replies."},{"id":"typing-indicator-dots","group":"ui-mockup","name":"Typing-indicator bouncing dots","what":"The three-dot 'typing…' bubble bounces, implying someone (or no one) is about to reply.","how":"`.typing i{width:16px;height:16px;border-radius:50%;background:#7c8088}` x3, then `tl.to('#typ5 i',{y:-10,duration:0.28,repeat:6,yoyo:true,stagger:0.09,ease:'sine.inOut'},t)`. Repeat+yoyo is fine because it lives on the seekable timeline.","when":"Tension beat of waiting for a reply (usually before 'GONE')."},{"id":"sms-bubble-single","group":"ui-mockup","name":"Single SMS/auto-text bubble","what":"One large gradient text bubble pops in showing an auto-sent message ('Sorry we missed you…').","how":"`.sms{max-width:640px;padding:26px 34px;border-radius:28px;background:linear-gradient(135deg,#ff8f3c,var(--orange));color:#160a00}` with `.t` sub-caption, then `tl.fromTo('#s11sms',{opacity:0,scale:0.6,y:20},{opacity:1,scale:1,y:0,duration:0.35,ease:'back.out(1.9)'},t)`.","when":"Missed-call text-back, reactivation text — 'the message we send' value beats."},{"id":"chat-widget-in-page","group":"ui-mockup","name":"On-site chat widget","what":"A chat widget docked bottom-right inside the browser page trades bot/user/AI bubbles.","how":"`.widget{align-self:flex-end;width:78%;background:#0f1116;border-radius:22px}` containing `.cm.bot`/`.cm.usr`/`.cm.ai` bubbles (`.cm.bot.dead` = muted failure). AI answer pops `tl.fromTo('#ai1',{opacity:0,scale:0.6,y:20},{...back.out(1.9)},t)`.","when":"Contrasting a dumb bot ('didn't understand') vs a good AI chat that answers+books."},{"id":"bad-popup-with-big-x","group":"ui-mockup","name":"Newsletter popup with big red X","what":"A cheesy 'Join our newsletter' email-capture popup gets stamped with a huge red ✕.","how":"`.popup{background:#fbf9f4;color:#141414}` with `h3`, a fake `.field`, and a `.btn`; overlay `.bigx{position:absolute;inset:0;font-size:340px;color:var(--red);opacity:0}` then `tl.fromTo('#bigx',{opacity:0,scale:0.4,rotation:-20},{opacity:1,scale:1,rotation:0,duration:0.4,ease:'back.out(2.2)'},t)`.","when":"Showing the wrong solution ('a pop-up does none of that')."},{"id":"calendar-mockup","group":"ui-mockup","name":"Booking calendar with highlighted day","what":"A little calendar card pops in and a day gets a filled highlight dot to show a booking landing.","how":"`.cal` white card with `.top` header and a 7-col `.grid` of `i` cells; `.grid i.on::before` draws a green circle behind. `tl.fromTo('#cal11',{scale:0.8,rotation:-4,opacity:0},{scale:1,rotation:0,opacity:1,duration:0.4,ease:'back.out(1.9)'},t)` then `tl.fromTo('#cal11 .grid i.on',{scale:0.2},{scale:1","when":"'It books the appointment' proof."},{"id":"review-card-google","group":"ui-mockup","name":"5-star review card","what":"A light Google-style review card slides up with avatar, name, 'just now', five gold stars popping in, and the review text.","how":"`.rev{background:#fbf9f4;border-radius:28px}` with `.rh` avatar row and `.stars b` gold stars. Card: `tl.fromTo('#rev11',{opacity:0,y:40,scale:0.9},{opacity:1,y:0,scale:1,duration:0.4,ease:'back.out(1.6)'},t)`; stars stagger `tl.fromTo('#rev11stars b',{scale:0,opacity:0},{scale:1,opacity:1,duration:","when":"'one tap → live on Google' review proof."},{"id":"star-rating-pop","group":"data-viz","name":"Star rating stagger pop","what":"A row of stars fills in one-by-one with a bounce.","how":"`.stars b{color:var(--gold);text-shadow:0 0 18px}` then `tl.fromTo('.stars b',{scale:0,opacity:0},{scale:1,opacity:1,duration:0.25,stagger:0.06-0.08,ease:'back.out(2.4)'},t)`.","when":"Reviews/ratings payoff; can accompany a gap counter."},{"id":"crm-list-rows-wake","group":"ui-mockup","name":"CRM list: cold rows → alive rows","what":"A CRM list of 'maybe later' leads fades cold, then a reactivation list wakes each row to 'replied ✓ / booked ✓'.","how":"`.crm .row` list; cold: `tl.fromTo(row,{opacity:0,x:-20},{opacity:1,x:0,...},t).to(row,{opacity:0.4,duration:0.5},coldTime)`. Alive: `.row.alive{background:rgba(255,107,0,.08)}` and `tl.fromTo('#c9a',{opacity:0.3,scale:0.96},{opacity:1,scale:1,duration:0.35,ease:'back.out(1.6)'},t)` staggered.","when":"Dead-lead reactivation stories (before/after the same list)."},{"id":"ai-answer-box","group":"ui-mockup","name":"AI search answer box","what":"A ChatGPT-style card shows a user question and a ranked '✨ AI answer' list; a red '✗ you're not here' or a highlighted '1. Your Business ✓' row lands.","how":"`.aibox` with `.q` (question + `.u` avatar dot) and `.a` list of `.item` / `.item.you` / `.miss`. Miss: `tl.fromTo('#s3miss',{opacity:0,x:-20},{opacity:1,x:0,duration:0.3,ease:'power2.out'},t)`. Win: `tl.fromTo('#s12you',{opacity:0,scale:0.7},{opacity:1,scale:1,duration:0.4,ease:'back.out(2)'},t)`.","when":"AI-search visibility ('did AI recommend you?') beats."},{"id":"phone-device-mockup","group":"ui-mockup","name":"Phone device with ring pulse","what":"A phone-shaped card shows a missed call, with a ring outline pulsing outward.","how":"`.phone{width:300px;height:600px;border-radius:52px;background:#14161c}` (`.phone.missed` red border), inner `.ring{position:absolute;inset:-2px;border:3px solid var(--orange);opacity:0}` then `tl.fromTo('#s1ring',{scale:1,opacity:0.8},{scale:1.15,opacity:0,duration:0.6,repeat:2,ease:'power1.out'},t","when":"Missed-call / phone-based hooks."},{"id":"phone-ring-shake","group":"motion-impact","name":"Ringing phone shake then dim","what":"A phone image rattles rapidly (ringing) then fades/shrinks as the call dies into the void.","how":"`tl.to('#s7phone',{rotation:6,duration:0.06,repeat:9,yoyo:true,ease:'sine.inOut'},t)` then `tl.to('#s7phone',{opacity:0.15,scale:0.9,duration:0.6,ease:'power2.in'},t2)`. Flowmap variant shakes a whole `.panel` with `x:8` repeats.","when":"'rings into the void' / unanswered-call beats."},{"id":"arrow-handoff-shoot","group":"motion-impact","name":"Hand-off arrow shoot","what":"An arrow between 'your caller' and 'competitor' shoots in, implying the lead going elsewhere.","how":"Two `.who` avatar tiles with an `.arrow` between; `tl.fromTo('#s2arrow',{x:-20,opacity:0.4},{x:0,opacity:1,duration:0.35,ease:'power3.out'},t)`. Competitor tile styled `.who.comp` green.","when":"'It calls the next guy' / customer leaving to a competitor."},{"id":"tool-chip","group":"ui-mockup","name":"Named tool chip","what":"A branded software chip (Zapier, Tidio, Chatbase, GoHighLevel) with a colored initial badge pops in.","how":"`.toolchip{background:#14161c;border:1.5px solid #2a2f3a;border-radius:20px} .toolchip .ic` gradient square initial + `.nm` name; `tl.fromTo('#t1',{opacity:0,scale:0.7,y:20},{opacity:1,scale:1,y:0,duration:0.35,ease:'back.out(1.9)'},t)`. Name word uses .w reveal.","when":"Naming real tools during the free-value / how-to beat."},{"id":"flow-diagram-boxes-arrows","group":"ui-mockup","name":"Left-to-right flow diagram","what":"Boxes and arrows lay out a pipeline: 📩 new lead → [Zapier] → auto-reply bubble.","how":"`.flow{display:flex;align-items:center;gap:22px;flex-wrap:wrap} .fbox`, `.farrow` (→), a `.toolchip`, and `.fbox.msg` gradient result. Whole flow fades up `tl.fromTo('#s9flow',{opacity:0,y:30},{opacity:1,y:0,duration:0.4,ease:'power2.out'},t)`.","when":"Explaining an automation as a simple pipeline."},{"id":"checklist-tick-reveal","group":"ui-mockup","name":"Checklist with ticking boxes","what":"List rows slide in and a checkbox tick scales in with a glow, one per beat.","how":"`.li/.fix` rows with `.cb` box and `.cb .tick{transform:scale(0)}`. Per row: `tl.fromTo(row,{opacity:0.2,x:-30},{opacity:1,x:0,duration:0.3,ease:'power2.out'},t); tl.fromTo(row+' .tick',{scale:0},{scale:1,duration:0.35,ease:'back.out(2.6)'},t+0.25); tl.fromTo(row+' .cb',{boxShadow:'0 0 0 rgba(255,10","when":"'3 things the visitor wants' / 'the 3 fixes' teaching lists."},{"id":"step-circles-milestone","group":"data-viz","name":"Numbered step circles with milestone","what":"A row of numbered circles 1–5 where the 5th is the green 'SALE ✓' milestone that pops.","how":"`.steps` flex row of `.step` circles; `.step.sale{border-color:var(--green);box-shadow:0 0 30px}` with a `.tag` label. `tl.fromTo('#step5',{scale:0.5},{scale:1,duration:0.4,ease:'back.out(2.2)'},t)`.","when":"'most sales close after the 5th follow-up' style stat."},{"id":"role-chips-pile","group":"ui-mockup","name":"Owner role-chips pile-in","what":"A stack of 'you answer the calls / you send the quotes…' chips piles in from the left, one per beat, to show overload.","how":"`.roles` column of `.role` rows (`.role .b` orange 'you'). Per row: `tl.fromTo('#r1',{opacity:0,x:-40,scale:0.95},{opacity:1,x:0,scale:1,duration:0.3,ease:'back.out(1.6)'},beat)`. Each row scored with its own pop SFX track.","when":"'you ARE the business' overwhelm sequence."},{"id":"system-card-rows-tick","group":"ui-mockup","name":"AI system card with ticking rows","what":"A single 'one AI' card lists the jobs it does, each row with a solid green check sliding in.","how":"`.sys` card, `.sys .r` rows each with `.ck` filled green circle check; per row `tl.fromTo('#sy1',{opacity:0,x:-30},{opacity:1,x:0,duration:0.3,ease:'power2.out'},beat)`.","when":"The 'one system replaces all those jobs' payoff."},{"id":"landing-page-mockup","group":"ui-mockup","name":"Clean landing-page mockup","what":"A tidy one-offer, one-button landing page card rises in as the 'fix'.","how":"`.lp{background:#fbf9f4;border-radius:22px} .lp .bar` fake browser dots, `.lp .body` with `h3` offer + `.btn` orange CTA; `tl.fromTo('#lp9',{opacity:0,y:40,scale:0.9},{opacity:1,y:0,scale:1,duration:0.4,ease:'back.out(1.6)'},t)`.","when":"Contrasting a leaky funnel with 'one clear page'."},{"id":"verdict-card","group":"ui-mockup","name":"Verdict summary card","what":"A large bordered card states a side's verdict ('costs a full salary and still misses half your calls') with a colored theme.","how":"`.verdict{width:820px;padding:52px 56px;border-radius:34px}` themed `.v-red`/`.v-lime` (gradient bg + colored border + shadow) holding `.vk` mono kicker and `.vbig` big statement; can carry a strike bar and a check pop. Card jolts `tl.fromTo('.v-red',{x:-8},{x:0,duration:0.5,ease:'elastic.out(1,0.3)","when":"Summarizing each side of a comparison before the question/CTA."},{"id":"gap-counter-vs","group":"data-viz","name":"Gap counter (200 vs 11)","what":"Two big numbers sit either side of a 'vs' / '→' to dramatize a gap (200 happy vs 11 reviews; 11/yr → 4/wk).","how":"`.gap{display:flex;gap:70px} .gcol` columns with `.gbig`/`.gsm` numbers and `.gcap` mono labels, a `.vs` separator. Numbers reveal via .w; can pair with star pop.","when":"Before/after or expectation-vs-reality numeric contrasts."},{"id":"progress-bars-scalex","group":"data-viz","name":"Horizontal progress/compare bars","what":"Track bars fill from the left to encode magnitudes (21x vs cratered, cost vs calls-captured, human vs AI).","how":"`.track{height:46-52px;border-radius;background:rgba(255,255,255,.06);overflow:hidden} .fill{transform-origin:left;transform:scaleX(0)}` themed `.fill.o`/`.fill.r`; animate `tl.to('#bar5',{scaleX:1,duration:0.8,ease:'power2.out'},t)` and a short one `tl.to('#bar30',{scaleX:0.05,...})`. Labels show t","when":"Any two-metric comparison or single filling stat."},{"id":"happiness-curve-draw","group":"data-viz","name":"Self-drawing curve with peak/late markers","what":"A satisfaction curve draws itself; a red marker sits at the 'you asked here (too late)' point, an orange marker at the 'peak happy' point.","how":"Inline SVG `path.cpath` (gray) and `.cpath.draw` (orange, drop-shadow). Draw via `tl.fromTo('#curve9 .cpath',{strokeDasharray:1200,strokeDashoffset:1200},{strokeDashoffset:0,duration:1.0,ease:'power1.inOut'},t)`. HTML `.mk.peak`/`.mk.late` dots positioned by left/top %, popped `tl.fromTo('#mk9',{sca","when":"Timing/moment arguments (ask at the peak, not late)."},{"id":"waveform-bars-seeded","group":"data-viz","name":"Audio waveform bars (seeded random)","what":"A row of bars jitters up and down like a live voice waveform while an AI 'speaks'.","how":"`.wave span{transform-origin:bottom/center}` bars; a driver builds many tiny tweens per bar using the seeded rnd(): `document.querySelectorAll('#wave span').forEach(b=>{let t=from;while(t<to){tl.to(b,{scaleY:0.4+rnd()*1.6,duration:0.12,ease:'sine.inOut',overwrite:'auto'},t);t+=0.11+rnd()*0.06;}tl.se","when":"AI-voice / 'answers the call' beats needing living audio feedback."},{"id":"leaky-bucket","group":"data-viz","name":"Leaky-bucket money drops","what":"An SVG bucket with holes shows '$4 left' while '$' drops fall out of the holes and fade.","how":"Inline SVG bucket path with hole circles and a `<text id=bkleft>$4`; HTML `.drop` '$' glyphs positioned at the holes, each `tl.fromTo('#d1',{opacity:0,y:0},{opacity:1,y:80,duration:0.6,ease:'power1.in'},t).to('#d1',{opacity:0,duration:0.1},t+0.6)`. Caption '.instat' counts 100 clicks in → 96 gone vi","when":"Wasted ad-spend / funnel-leak metaphor."},{"id":"equation-build-math","group":"data-viz","name":"Stacked equation build to a total","what":"Math lines appear one at a time (14 calls/wk × 1 in 4 × $600) then a giant total counts up and gets struck/dimmed.","how":"`.mathwrap` column of `.ml{opacity:0}` lines; each `tl.fromTo('#ml1',{opacity:0,y:30},{opacity:1,y:0,duration:0.3,ease:'power2.out'},beat)`. Total counts via the money-count-up proxy, then land+dim `tl.to('#bignum',{color:'#59636f',textShadow:'0 0 0',duration:0.3},t)` + strike bar scaleX + a mono fo","when":"'Watch — here's the math' cost-of-inaction proofs."},{"id":"clock-counter-tick","group":"data-viz","name":"Live waiting-clock counter","what":"A mono '⏱ NN min waiting…' readout ticks upward to dramatize a lead going cold.","how":"`tl.to(ck,{v:47,duration:2.4,ease:'none',onUpdate:()=>{el.textContent='⏱ '+Math.round(ck.v)+' min waiting...';}},t)` on a proxy `{v:0}` — deterministic on scrub.","when":"Speed-to-lead hooks where elapsed time is the villain."},{"id":"count-up-people","group":"data-viz","name":"People/quantity count-up","what":"A non-money figure rolls up (e.g. 0 → 214 happy customers).","how":"Proxy tween writing an integer: `tl.to(h,{v:214,duration:1.6,ease:'power1.out',onUpdate:()=>{el.textContent=Math.round(h.v);}},t)`. Same engine as money count-up without currency formatting.","when":"'you've made hundreds happy' style volume hooks."},{"id":"roster-ring-build","group":"layout","name":"Avatar roster ring build","what":"Avatars are placed evenly around a circle and light up one-by-one with a star, forming a 'full roster' ring.","how":"Programmatic (seeded/deterministic, no random): loop k with `const ang=(k/8)*Math.PI*2,R; a.style.left=(50+Math.cos(ang)*40)+'%'; a.style.top=(50+Math.sin(ang)*40)+'%'`, append star span. Animate `tl.fromTo(a,{scale:0,opacity:0},{scale:1,opacity:1,duration:0.3,ease:'back.out(2)'},base+k*0.05)` then ","when":"'same customers, more results' roster payoffs (reviews)."},{"id":"leak-dots-scatter-fade","group":"data-viz","name":"Scattered lead-dots that vanish","what":"Dozens of glowing dots (incoming leads) appear across a box, then most quietly fade away.","how":"Dots built from a fixed position array (deterministic). Appear staggered `tl.fromTo(d,{opacity:0,scale:0.2},{opacity:1,scale:1,duration:0.25,ease:'back.out(2)'},3.1+i*0.13)`; then most fade `if(i%3!==0) tl.to(d,{opacity:0.12,scale:0.7,duration:0.5,ease:'power2.in'},5.6+i*0.05)`.","when":"'people reach out and quietly disappear' leak hooks."},{"id":"camera-rig-pan-rotate","group":"3d","name":"Camera rig pan around a ring of nodes","what":"The view seems to arc/pan around a looped ring of problem nodes while a dot travels the ring.","how":"A `.rig{position:absolute;left:50%;top:50%}` holds `.node` cards positioned by left/top; pan by rotating the rig `tl.fromTo('#loopRig',{rotation:-20},{rotation:20,duration:3.6,ease:'sine.inOut'},t)`. Nodes pop `tl.fromTo('#lp1',{opacity:0,scale:0.7},{opacity:1,scale:1,duration:0.35,ease:'back.out(1.","when":"Showing a repeating loop/cycle (the human's weekly problem loop)."},{"id":"camera-rig-track-down","group":"3d","name":"Camera rig track-down a stack","what":"The camera glides downward past a vertical stack of capability nodes as each appears with a check.","how":"`tl.fromTo('#stackRig',{y:220},{y:-360,duration:4.3,ease:'power1.inOut'},t)` moves the rig; a vertical connector draws `tl.fromTo('#stackPath',{strokeDashoffset:1200},{strokeDashoffset:0,duration:4.0,ease:'none'},t)`; nodes enter `tl.fromTo(id,{opacity:0,x:60,scale:0.9},{opacity:1,x:0,scale:1,durati","when":"'what it does on autopilot' capability stacks."},{"id":"connector-path-draw","group":"3d","name":"Dashed connector self-draw","what":"A dashed glowing line draws itself between/through nodes to imply flow.","how":"SVG `.flow path{stroke-dasharray:'10 14';filter:drop-shadow(0 0 10px currentColor)}` animated via strokeDashoffset from a large value to 0 with ease:'none'. Ring path uses an `A`(arc) command; stack path a vertical `V` line.","when":"Flow-map style explainers linking nodes."},{"id":"moving-dot-along-path","group":"3d","name":"Dot traveling a path","what":"A glowing dot circulates around the loop path.","how":"Approximated with rotation about the ring center: `tl.fromTo('#loopDot',{rotation:0,svgOrigin:'540 920'},{rotation:360,duration:3.2,ease:'none'},t)` (GSAP svgOrigin). `.dotmove{fill:currentColor;filter:drop-shadow}`.","when":"Signaling continuous motion around a cycle."},{"id":"node-check-badge","group":"3d","name":"Node check-badge pop","what":"A small orange ✓ badge pops onto the corner of a capability node.","how":"`.chk{position:absolute;right:-14px;top:-14px;width:52px;height:52px;border-radius:50%;background:var(--orange)}` then `tl.fromTo(id+' .chk',{scale:0},{scale:1,duration:0.35,ease:'back.out(2.4)'},t+0.5)`.","when":"Confirming each item in a flow-map capability stack."},{"id":"glass-panel-node","group":"ui-mockup","name":"Frosted glass panel node","what":"A translucent, blurred glass card with an icon and title represents an entity (Human receptionist / AI receptionist).","how":"`.panel{background:rgba(26,27,31,.62);border:1.5px solid rgba(255,255,255,.14);border-radius:26px;backdrop-filter:blur(7px);box-shadow:...,inset 0 1px 0 rgba(255,255,255,.09)}` with `.ic` inline-SVG line icon and `.tx b/small`. Rim variants `.rimO`/`.rimR` add colored glow + tint the icon stroke. En","when":"Flow-map / premium-dark reels labeling entities as glass nodes."},{"id":"corner-collage-cards","group":"layout","name":"Rotated collage corner cards","what":"Grayscale photo cards with mono captions sit in the four corners, popping in from their edges and slowly drifting/tilting.","how":"`.corner{position:absolute;border:3px solid;box-shadow:9px 11px 0 rgba(0,0,0,.13)}` with `<img>`(grayscale contrast) + `.clbl` caption + a halftone `::after`. Positioned via inline top/left/right/bottom and `data-rot`. Per card: `tl.fromTo(c,{opacity:0,scale:0.7,x:±70,y:30,rotation:0},{opacity:1,sca","when":"Asset-rich 'rami-style' collage reels for texture around the message."},{"id":"cutout-image-blend","group":"ui-mockup","name":"Grayscale cut-out image with blend","what":"A subject photo is desaturated and blended into the paper/black background (multiply on light, screen on dark).","how":"`.cut{filter:grayscale(1) contrast(1.16) brightness(1.03)}` with `.cut.onP{mix-blend-mode:multiply}` (on paper) and `.cut.onK{mix-blend-mode:screen}` (on black). Placed inside `.frame`.","when":"Editorial photo integration that stays on-palette."},{"id":"compare-chat-win-lose","group":"ui-mockup","name":"Win/lose message compare","what":"A green 'WINS' quick message sits above a struck-through gray 'TOO LATE' perfect quote to show speed beats polish.","how":"`.cmsg.win{background:linear-gradient(135deg,#5ee892,#22c55e)}` vs `.cmsg.lose{background:#232732;text-decoration:line-through;text-decoration-color:#ff6a62}`, each with a `.tg.g`/`.tg.r` pill tag. Enter from opposite sides: `tl.fromTo('#s11win',{opacity:0,x:-40,scale:0.9},{opacity:1,x:0,scale:1,...","when":"'fast good-enough beats slow perfect' comparisons."},{"id":"vignette-overlay","group":"ambience","name":"Vignette overlay","what":"Edges of the frame darken to focus the eye center.","how":"`#vign{position:absolute;inset:0;z-index:71;background:radial-gradient(120% 85% at 50% 42%,transparent 55%,rgba(0,0,0,.45) 100%)}`. Static overlay in every reel.","when":"Always-on base focus layer."},{"id":"halftone-dot-overlay","group":"ambience","name":"Halftone dot screen","what":"A fine printed-dot pattern overlays the frame for a risograph/print feel.","how":"`#halftone{inset:0;opacity:.16;mix-blend-mode:multiply;background-image:radial-gradient(rgba(0,0,0,.9) 1.1px,transparent 1.4px);background-size:7px 7px}` (reel 21b).","when":"Print/collage-styled reels."},{"id":"dot-grid-world","group":"ambience","name":"Dot-grid world + center glow","what":"A dotted grid fills the background with a warm orange glow pooled at center.","how":"`#world{background-image:radial-gradient(rgba(255,255,255,.09) 1.4px,transparent 1.6px);background-size:40px 40px}` + `#glow{background:radial-gradient(60% 40% at 50% 44%,rgba(255,107,0,.10),transparent 70%)}` (flowmap). Static.","when":"Single-world flow-map reels (no bg color rotation)."},{"id":"grid-lines-background","group":"ambience","name":"Engineering grid-line background","what":"Faint square grid lines under the paper/black backgrounds give a blueprint feel.","how":"`.bg-paper`/`.bg-black` layer `linear-gradient(0deg,var(--gridw) 1px,transparent 1px),linear-gradient(90deg,...)` at `background-size:64px 64px` over a radial base (reel 21b).","when":"Structured/'systems' aesthetic backdrops."},{"id":"watermark-footer","group":"ambience","name":"Brand watermark footer","what":"A faint spaced-out 'A I S Y S T E M S' sits at the bottom.","how":"`.wm{position:absolute;bottom:40px;left:0;right:0;text-align:center;font-family:Space Mono;letter-spacing:.35em;opacity:.26}` with color adapted per background (`.bg-o .wm,.bg-w .wm{color:#5a4632}` vs black `#777`).","when":"Persistent brand mark on every frame."},{"id":"eyebrow-mono-label","group":"kinetic-type","name":"Mono eyebrow / kicker label","what":"A small uppercase spaced-out mono label sits above or below a headline ('THE STUDY', 'salary · benefits · overhead', 'the human loop').","how":"`.lbl/.eyebrow/.kick{font-family:Space Mono;font-weight:700;letter-spacing:.28-.34em;text-transform:uppercase;color:var(--dim)}`. Often static context; when animated it uses the standard .w reveal.","when":"Framing/labeling a stat or section without competing with the head."},{"id":"brand-bars-signoff","group":"layout","name":"Brand color-bars sign-off","what":"A row of short color bars (lime/blue/orange/off-white) draw out under the final 'Plug the leak.' logotype.","how":"`.brandbars span{width:96px;height:16px;border-radius:8px}` colored per brand; group fades `tl.fromTo('#bars',{opacity:0,y:20},{opacity:1,y:0,duration:0.4,ease:'back.out(1.6)'},t)` then each bar draws `tl.fromTo(s,{scaleX:0},{scaleX:1,duration:0.25,ease:'power2.out',transformOrigin:'left center'},t+","when":"Branded end-card / sign-off."},{"id":"check-pop-rotate","group":"motion-impact","name":"Check-mark pop with rotate","what":"A ✓ springs in with a slight rotate to confirm 'misses nothing'.","how":"`tl.fromTo('#v16chk',{opacity:0,scale:0.4,rotation:-20},{opacity:1,scale:1,rotation:0,duration:0.45,ease:'back.out(2.4)'},t)`, often paired with a glow tween on the parent card `tl.to('.v-lime',{boxShadow:'0 30px 90px rgba(184,255,44,.35)',duration:0.4},t)`.","when":"Positive confirmation punctuation at the end of a verdict."},{"id":"tension-scale-drift","group":"motion-impact","name":"Slow tension scale-drift","what":"A question headline slowly creeps larger to build tension (usually under a reverse-riser SFX).","how":"`tl.fromTo(sel+' .head',{scale:0.97},{scale:1,duration:1.2,ease:'power1.out'},t)` — a long slow scale under a held beat.","when":"The rhetorical 'so which… ?' question before the CTA."},{"id":"dim-fade-out","group":"motion-impact","name":"Dim/fade-to-void","what":"An element loses brightness/opacity to signify death of a call/lead.","how":"`tl.to(target,{opacity:0.15-0.2,scale:0.9,duration:0.5-0.6,ease:'power2.in'},t)`. Used after the ring-shake to send a phone into the void.","when":"Concluding a 'lost/ignored' beat."}];
